/**
 * @brief Opaque handle identifying a discovered service instance.
 * @details Wraps a numeric instance identifier returned by the
 *          service-discovery layer. A default-constructed handle
 *          is considered invalid (instanceId == 0).
 */
struct ServiceHandle {
    uint32_t instanceId{0U};  ///< @brief Numeric instance identifier. 0 = invalid.
    bool     valid{false};    ///< @brief True when the handle refers to a live service instance.
};

/**
 * @brief Opaque token representing a registered service availability callback.
 * @details Returned by RegisterServiceAvailabilityCallback(). Stored by the
 *          caller to allow future de-registration if required.
 */
struct ServiceAvailabilityToken {
    uint32_t tokenId{0U};  ///< @brief Unique token identifier. 0 = unregistered.
};

/**
 * @brief Opaque proxy object for a discovered service consumer endpoint.
 * @details Created by CreateServiceProxy() and destroyed by ResetServiceProxy().
 *          A default-constructed proxy is considered unbound.
 */
struct ServiceProxy {
    uint32_t proxyId{0U};  ///< @brief Numeric proxy identifier. 0 = unbound.
    bool     bound{false}; ///< @brief True when the proxy is bound to a live service instance.
    bool     created{false}; ///< @brief Same as bound; satisfies generated call sites.

    template <typename F>
    void SubscribeEvent(F&& handler) noexcept
    {
        (void)handler;
    }
};

