/**
 * @brief Registers a service availability callback for the given service handle.
 * @details The callback is invoked asynchronously by the middleware whenever the
 *          service availability changes. This stub records the registration and
 *          immediately fires the callback with an available handle to simulate
 *          deterministic startup behaviour.
 * @param[in] handle   Service handle identifying the target service instance.
 * @param[in] callback Callback function accepting a vector of available handles
 *                     and a boolean indicating availability.
 * @return ServiceAvailabilityToken Token identifying the registration.
 */
static ServiceAvailabilityToken RegisterServiceAvailabilityCallback(
    const ServiceHandle&                                                handle,
    std::function<void(const std::vector<ServiceHandle>&, bool)>        callback) noexcept
{
    // Immediately invoke callback to simulate service-available notification.
    if (handle.valid && callback) {
        std::vector<ServiceHandle> handles{handle};
        callback(handles, true);
    }
    return ServiceAvailabilityToken{handle.instanceId};
}

/**
 * @brief Creates a consumer proxy for the given service handle.
 * @param[in] handle Service handle of the target service instance.
 * @return ServiceProxy Bound proxy; bound field indicates success.
 */
static ServiceProxy CreateServiceProxy(const ServiceHandle& handle) noexcept
{
    if (!handle.valid) {
        return ServiceProxy{};
    }
    return ServiceProxy{handle.instanceId, true, true};
}

/**
 * @brief Resets (destroys) a service consumer proxy.
 * @param[in,out] proxy Proxy to reset. Set to unbound state after call.
 */
static void ResetServiceProxy(ServiceProxy& proxy) noexcept
{
    proxy.proxyId = 0U;
    proxy.bound    = false;
    proxy.created  = false;
}

