/**
 * @brief Constructs ProbeComm with a variant reference for communication setup.
 * @details Performs deterministic initialization of all private communication-state
 *          members to their defined default values. Stores the variant pointer for
 *          subsequent use by communication and variant-checking functions. Evaluates
 *          the compile-time BUILD_CONFIG constant to set devLogEnabled_ appropriately.
 *          No heap allocation is performed after this constructor returns.
 *
 *          Initialization order follows the pseudocode exactly:
 *          1. Store variant pointer.
 *          2. Initialize all boolean flags to false.
 *          3. Zero all retry counters and process counters.
 *          4. Clear the category trigger map.
 *          5. Zero all trigger-state, log-time, image, and segmentation fields.
 *          6. Set accepted arrays to default values (0x00 / 0x00000000).
 *          7. Set configurable parameters to their specified initial values.
 *          8. Set devLogEnabled_ based on BUILD_CONFIG.
 *          9. Initialize imageTimeoutTimerStarted_ to false.
 *          Mutexes are default-constructed and immediately ready for use.
 *
 * @param[in] variant Pointer to the ProbeCommVariant configuration structure.
 *                    Must not be nullptr. Lifetime must exceed this object's lifetime.
 * @pre  variant != nullptr and points to a valid, fully initialized ProbeCommVariant.
 * @post All internal counters are zero. All flags are false. Mutexes are unlocked.
 *       devLogEnabled_ reflects the build configuration.
 * @throws None — constructor is noexcept after parameter validation.
 * @note Called by: ProbeApp at startup.
 * @warning Passing a nullptr variant results in undefined behavior.
 * @requirements SWR-REQ-01-04-001;SWR-REQ-03-16-002
 * @rationale Variant-based initialization allows compile-time variant selection
 *            without runtime branching in the communication hot path.
 */
ProbeComm::ProbeComm(ProbeCommVariant* const variant) noexcept
    : variant_{variant}
    , daqCommunicationEstablished_{false}
    , zatTriggerReceived_{false}
    , cameraAnswerBackReceived_{false}
    , imageAcquisitionComplete_{false}
    , bdpRequestRetryCounter_{0U}
    , bdpTransmitRetryCounter_{0U}
    , gedrWriteRetryCounter_{0U}
    , activeEventProcessCount_{0U}
    // , categoryTriggerCountMap_null
    , currentDataTransmissionNum_{0U}
    , currentCategoryIdentifier_{0U}
    , dataUploadRequestFlg_{0U}
    , effectiveLogStartTime_{0}
    , effectiveLogEndTime_{0}
    , imageFrameCounter_{0U}
    , receivedImageCount_{0U}
    , eventDataFrameCounter_{0U}
    , segmentNumber_{0U}
    , totalSegments_{0U}
    , acceptedDataTransmissionNum_{0U}
    , acceptedCategoryIdentifier_{0U}
    , allowedOverlapTriggerNum_{1U}
    , imageAcquisitionTimeoutSec_{55U}
    , bdpRetryIntervalMs_{8000U}
    , bdpMaxRetryCount_{5U}
    , gedrMaxRetryCount_{5U}
    , sameCategoryLimitPerDC_{5U}
    , devLogEnabled_{false}
    , imageTimeoutTimerStarted_{false}
    // , imageTimeoutStartPoint_nullnull
    // , sendBufferMutex_null
    // , cameraMutex_nullnull
{
    // Accepted arrays are initialized via member-initializer list above.
    // Explicitly set each slot to its defined default value per pseudocode.
    acceptedDataTransmissionNum_ = 0x00U;
    acceptedCategoryIdentifier_  = 0x00000000U;

    // Evaluate build configuration to set devLogEnabled_.
    // BUILD_CONFIG is a compile-time constant: define DEVELOPMENT to enable logging.
#if defined(BUILD_CONFIG) && (BUILD_CONFIG == DEVELOPMENT)
    devLogEnabled_ = true;
#else
    devLogEnabled_ = false;
#endif

    // categoryTriggerCountMap_ is default-constructed as an empty map,
    // representing the start of a new driving cycle with no acceptance history.
    // (Already initialized via member-initializer list.)

    // sendBufferMutex_ and cameraMutex_ are default-constructed and
    // immediately available for thread-safe operation.
    // (Already initialized via member-initializer list.)
}

