/**
 * @brief Destructor. Releases all owned resources.
 * @details Stops any active timers, resets all state, and ensures no dangling
 *          references remain. All std::mutex members are destroyed by their
 *          own destructors. The variant_ pointer is non-owning and is not deleted.
 * @pre  None.
 * @post All resources are released. No dangling references remain.
 * @throws None.
 */
ProbeComm::~ProbeComm() noexcept
{
    // Reset all flags to safe defaults before destruction.
    daqCommunicationEstablished_.store(false);
    zatTriggerReceived_          = false;
    cameraAnswerBackReceived_    = false;
    imageAcquisitionComplete_    = false;
    imageTimeoutTimerStarted_    = false;
    devLogEnabled_               = false;

    // Clear the category map to release any heap-allocated nodes.
    categoryTriggerCountMap_.clear();

    // variant_ is non-owning; do not delete.
    variant_ = nullptr;
}

