// PC-002 : FindServiceDaqContinual
// ============================================================

/**
 * @brief Locates the DAQ SOME/IP continual data service for steady-state data transmission.
 * @details Resolves the CORE_DAQ_continual_Service instance identifier via
 *          ResolveContinualServiceInstanceId(). If the identifier is invalid, logs
 *          an error and returns. Otherwise registers the OnContinualServiceAvailabilityChanged
 *          callback via RegisterServiceAvailabilityCallback(). The callback acquires
 *          sendBufferMutex_ and updates daqCommunicationEstablished_ atomically when
 *          the service availability changes. The function itself returns immediately
 *          after callback registration; all subsequent state updates are driven
 *          asynchronously by the registered callback.
 *
 * @pre  ProbeComm has been constructed with a valid variant.
 * @post daqCommunicationEstablished_ may transition to true upon service availability.
 * @throws None.
 * @note Called by: ProbeApp at startup. Provides: CORE_DAQ_continual_Service.
 * @warning Blocks until service is found or a platform-defined timeout expires.
 * @requirements SWR-REQ-01-04-001;SWR-REQ-01-06-003;SWR-REQ-03-16-002
 * @rationale Separate find functions per service allow independent retry and
 *            fault isolation per SOME/IP service endpoint.
 */
void ProbeComm::FindServiceDaqContinual() noexcept
{
    // Resolve the service instance identifier for CORE_DAQ_continual_Service.
    const ServiceHandle continualServiceInstanceId{ResolveContinualServiceInstanceId()};

    if (!continualServiceInstanceId.valid) {
        // Log error and return; retry will be attempted on next startup cycle
        // by the execution lifecycle manager.
        LogError("CORE_DAQ_continual_Service instance ID resolution failed");
        return;
    }

    // Register availability callback for CORE_DAQ_continual_Service.
    // The lambda captures 'this' by pointer; lifetime is guaranteed by ProbeApp.
    RegisterServiceAvailabilityCallback(
        continualServiceInstanceId,
        [this](const std::vector<ServiceHandle>& handles, const bool isAvailable) noexcept {
            // CALLBACK OnContinualServiceAvailabilityChanged
            if (isAvailable && !handles.empty()) {
                // Service found: update internal communication flag.
                {
                    std::lock_guard<std::mutex> lock{sendBufferMutex_};
                    daqCommunicationEstablished_.store(true);
                }
                LogInfo("CORE_DAQ_continual_Service available; daqCommunicationEstablished = true");
            } else {
                // Service lost: suppress transmission until rediscovery.
                {
                    std::lock_guard<std::mutex> lock{sendBufferMutex_};
                    daqCommunicationEstablished_.store(false);
                }
                LogInfo("CORE_DAQ_continual_Service unavailable; daqCommunicationEstablished = false");
            }
        });

    // Asynchronous discovery initiated; function returns after callback registration.
    // daqCommunicationEstablished_ will be updated by the callback when service is found.
}

