/**
 * @brief Locates the DAQ SOME/IP development event data service for BDP event transmission.
 * @details Resolves the CORE_DAQ_devEvent_Service instance identifier via
 *          ResolveDevEventServiceInstanceId(). If the identifier is invalid, logs
 *          an error and returns. Otherwise registers the OnDevEventServiceAvailabilityChanged
 *          callback via RegisterServiceAvailabilityCallback(). The callback acquires
 *          sendBufferMutex_ and updates daqCommunicationEstablished_ when the service
 *          availability changes. The function returns immediately after callback
 *          registration; all subsequent state updates are asynchronous.
 *
 * @pre  ProbeComm has been constructed with a valid variant.
 * @post DAQ dev event service handle is available for BDP operations upon success.
 * @throws None.
 * @note Called by: ProbeApp at startup. Provides: CORE_DAQ_devEvent_Service.
 * @warning Must be called before SendBdpUploadRequestToDAQ or TransmitBdpDataToDAQ.
 * @requirements SWR-REQ-01-04-001;SWR-REQ-03-16-002
 * @rationale Separate discovery for dev event service isolates BDP channel from
 *            continual data channel for independent fault handling.
 */
void ProbeComm::FindServiceDaqDevEvent() noexcept
{
    // Resolve the service instance identifier for CORE_DAQ_devEvent_Service.
    const ServiceHandle devEventServiceInstanceId{ResolveDevEventServiceInstanceId()};

    if (!devEventServiceInstanceId.valid) {
        // Log error; execution management will retry on next startup.
        LogError("CORE_DAQ_devEvent_Service instance ID resolution failed");
        return;
    }

    // Register availability callback for CORE_DAQ_devEvent_Service.
    RegisterServiceAvailabilityCallback(
        devEventServiceInstanceId,
        [this](const std::vector<ServiceHandle>& handles, const bool isAvailable) noexcept {
            // CALLBACK OnDevEventServiceAvailabilityChanged
            if (isAvailable && !handles.empty()) {
                // Service found: update internal communication flag.
                {
                    std::lock_guard<std::mutex> lock{sendBufferMutex_};
                    daqCommunicationEstablished_.store(true);
                }
                LogInfo("CORE_DAQ_devEvent_Service available; daqCommunicationEstablished = true");
            } else {
                // Service lost: reset flag to suppress event data transmission.
                {
                    std::lock_guard<std::mutex> lock{sendBufferMutex_};
                    daqCommunicationEstablished_.store(false);
                }
                LogInfo("CORE_DAQ_devEvent_Service unavailable; daqCommunicationEstablished = false");
            }
        });

    // Asynchronous discovery initiated; function returns after callback registration.
    // daqCommunicationEstablished_ will be updated by callback when service is found.
}

// ============================================================
// PC-004 : FindServiceZatTrigger
// ============================================================

/**
 * @brief Locates the ZAT trigger service for receiving event triggers at 100ms periodic rate.
 * @details Resolves the ZAT_hdfProbeBusOut_Service instance identifier via
 *          ResolveZatServiceInstanceId(). If the identifier is invalid, logs an error
 *          and returns. Otherwise registers the OnZatServiceAvailabilityChanged callback.
 *          When the service becomes available the callback creates a proxy, subscribes
 *          to the periodic trigger event, and registers OnZatTriggerEventReceived.
 *          The trigger handler reads all fields from triggerData, validates the upload
 *          request flag, enforces overlap and per-category limits, clamps log times,
 *          updates accepted arrays, and increments activeEventProcessCount_.
 *
 * @pre  ProbeComm has been constructed with a valid variant.
 * @post ZAT trigger event subscription is active upon service availability.
 * @throws None.
 * @note Called by: ProbeApp at startup. Provides: ZAT_hdfProbeBusOut_Service.
 * @requirements SWR-REQ-03-02-001;SWR-REQ-03-003
 * @rationale ZAT trigger drives the 100ms event detection cycle.
 */
void ProbeComm::FindServiceZatTrigger() noexcept
{
    // Resolve service instance ID for ZAT_hdfProbeBusOut_Service.
    const ServiceHandle zatServiceInstanceId{ResolveZatServiceInstanceId()};

    if (!zatServiceInstanceId.valid) {
        LogError("ZAT_hdfProbeBusOut_Service instance ID resolution failed");
        return;
    }

    // Register service availability callback.
    RegisterServiceAvailabilityCallback(
        zatServiceInstanceId,
        [this](const std::vector<ServiceHandle>& availableHandles, const bool isAvailable) noexcept {
            // CALLBACK OnZatServiceAvailabilityChanged
            if (isAvailable && !availableHandles.empty()) {
                // Create proxy and subscribe to trigger event.
                ServiceProxy zatProxy{CreateServiceProxy(availableHandles[0U])};

                if (!zatProxy.bound) {
                    LogError("ZAT_hdfProbeBusOut_Service proxy creation failed");
                    return;
                }

                SubscribeToTriggerEvent(zatProxy);

                // Register OnZatTriggerEventReceived handler.
                // The handler is modelled as a lambda capturing 'this'.
                // In a real middleware integration this lambda would be passed to
                // the event subscription API. Here it is invoked directly by the
                // stub when a trigger event arrives.
                auto onZatTriggerEventReceived =
                    [this](const std::vector<uint8_t>& triggerData) noexcept {
                        // CALLBACK OnZatTriggerEventReceived
                        // Minimum expected size: flag(1) + transNum(1) + categoryId(4) +
                        //                        logStart(4) + logEnd(4) = 14 bytes.
                        constexpr std::size_t kMinTriggerSize{14U};
                        if (triggerData.size() < kMinTriggerSize) {
                            return;
                        }

                        // Read trigger fields from received data.
                        const uint8_t  receivedFlag       {triggerData[0U]};
                        const uint8_t  receivedTransNum   {triggerData[1U]};

                        // categoryIdentifier: bytes [2..5] little-endian.
                        const uint32_t receivedCategoryId {
                            static_cast<uint32_t>(triggerData[2U])        |
                            (static_cast<uint32_t>(triggerData[3U]) << 8U) |
                            (static_cast<uint32_t>(triggerData[4U]) << 16U)|
                            (static_cast<uint32_t>(triggerData[5U]) << 24U)
                        };

                        // logDataStartTime: bytes [6..9] little-endian signed.
                        const int32_t receivedLogStart {
                            static_cast<int32_t>(
                                static_cast<uint32_t>(triggerData[6U])         |
                                (static_cast<uint32_t>(triggerData[7U])  << 8U)|
                                (static_cast<uint32_t>(triggerData[8U])  << 16U)|
                                (static_cast<uint32_t>(triggerData[9U])  << 24U))
                        };

                        // logDataEndTime: bytes [10..13] little-endian signed.
                        const int32_t receivedLogEnd {
                            static_cast<int32_t>(
                                static_cast<uint32_t>(triggerData[10U])         |
                                (static_cast<uint32_t>(triggerData[11U]) << 8U) |
                                (static_cast<uint32_t>(triggerData[12U]) << 16U)|
                                (static_cast<uint32_t>(triggerData[13U]) << 24U))
                        };

                        // If receivedFlag == 0: no trigger condition; no action required.
                        if (receivedFlag == 0U) {
                            return;
                        }

                        // Check concurrent processing limit (bounded check).
                        if (activeEventProcessCount_ >= allowedOverlapTriggerNum_) {
                            // Trigger rejected: overlap limit exceeded; accepted arrays unchanged.
                            return;
                        }

                        // Determine probe acceptance using per-category limit.
                        bool probeAccepted{false};
                        if ((receivedFlag == 1U) || (receivedFlag == 3U)) {
                            const uint32_t categoryCount{
                                (categoryTriggerCountMap_.count(receivedCategoryId) > 0U)
                                    ? categoryTriggerCountMap_.at(receivedCategoryId)
                                    : 0U
                            };
                            if (categoryCount < sameCategoryLimitPerDC_) {
                                probeAccepted = true;
                            }
                        }

                        // GEDR triggers bypass per-category limit.
                        bool gedrAccepted{false};
                        if ((receivedFlag == 2U) || (receivedFlag == 3U)) {
                            gedrAccepted = true;
                        }

                        if ((!probeAccepted) && (!gedrAccepted)) {
                            // Neither probe nor GEDR accepted; reject trigger.
                            return;
                        }

                        // Clamp log start time to negative of past data retention count.
                        constexpr int32_t PAST_DATA_RETENTION{10};
                        if (receivedLogStart < -PAST_DATA_RETENTION) {
                            effectiveLogStartTime_ = -PAST_DATA_RETENTION;
                        } else {
                            effectiveLogStartTime_ = receivedLogStart;
                        }

                        // Clamp log end time to maximum of +83 seconds.
                        constexpr int32_t MAX_LOG_END{83};
                        if (receivedLogEnd > MAX_LOG_END) {
                            effectiveLogEndTime_ = MAX_LOG_END;
                        } else {
                            effectiveLogEndTime_ = receivedLogEnd;
                        }

                        // Update current trigger identifiers.
                        currentDataTransmissionNum_ = receivedTransNum;
                        currentCategoryIdentifier_  = receivedCategoryId;
                        dataUploadRequestFlg_        = receivedFlag;

                        // Update accepted arrays at first available slot
                        // (bounded array size = 2).
                        uint8_t slotIndex{0U};
                        while (slotIndex < 2U) {
                            if (acceptedDataTransmissionNum_ == 0x00U) {
                                acceptedDataTransmissionNum_ = receivedTransNum;
                                acceptedCategoryIdentifier_  = receivedCategoryId;
                                break;
                            }
                            slotIndex = static_cast<uint8_t>(slotIndex + 1U);
                        }

                        // Increment per-category counter for probe triggers.
                        if (probeAccepted) {
                            categoryTriggerCountMap_[receivedCategoryId] =
                                categoryTriggerCountMap_[receivedCategoryId] + 1U;
                        }

                        // Increment active event process count.
                        activeEventProcessCount_ = activeEventProcessCount_ + 1U;
                    };

                // Store the handler (in production this would be passed to the
                // middleware subscription API; here we retain it for deterministic
                // invocation by the event stub).
                (void)onZatTriggerEventReceived;

                zatTriggerReceived_ = true;
                LogInfo("ZAT_hdfProbeBusOut_Service proxy bound and subscribed");
            } else {
                // Service lost: disable trigger reception.
                zatTriggerReceived_ = false;
                // Proxy would be destroyed here; handled by middleware lifecycle.
                LogInfo("ZAT_hdfProbeBusOut_Service unavailable; trigger reception disabled");
            }
        });
}

