/**
 * @brief Locates ZAT regular upload data service for receiving regular upload data.
 * @details Invokes RegisterServiceAvailabilityCallback() with ZAT_hdfProbeBusOut_Service
 *          and the OnZatRegularUploadServiceAvailability handler. When the service
 *          becomes available the callback iterates the available handles, creates a
 *          proxy for the matching instance, subscribes to the regular upload data event,
 *          and registers HandleZatRegularUploadData1Evt as the event handler. When the
 *          service disappears the proxy is reset. The function returns immediately after
 *          callback registration; the middleware manages discovery retry independently.
 *
 * @pre  ProbeComm has been constructed with a valid variant.
 * @post ZAT regular upload event subscription is active upon service availability.
 * @throws None.
 * @note Called by: ProbeApp at startup. Provides: ZAT_hdfProbeBusOut_Service.
 * @requirements SWR-REQ-01-01-001
 * @rationale Regular upload data provides steady-state signal collection independent
 *            of event triggers.
 */
void ProbeComm::FindServiceZatRegularUpload() noexcept
{
    // Step 1: Log entry into service discovery for ZAT regular upload.
    LogInfo("Starting FindService for ZAT_hdfProbeBusOut_Service (regular upload)");

    // Resolve the service instance identifier for ZAT_hdfProbeBusOut_Service.
    const ServiceHandle zatRegularUploadInstanceId{ResolveZatServiceInstanceId()};

    // Step 2: Invoke middleware service discovery for ZAT_hdfProbeBusOut_Service.
    // Register service availability callback handler.
    RegisterServiceAvailabilityCallback(
        zatRegularUploadInstanceId,
        [this, zatRegularUploadInstanceId](const std::vector<ServiceHandle>& availableHandles, const bool isAvailable) noexcept {
            // ON EVENT OnZatRegularUploadServiceAvailability(availableHandles)
            if (isAvailable && !availableHandles.empty()) {
                // Step 3a: Iterate through available service handles.
                for (const ServiceHandle& handle : availableHandles) {
                    if (handle.instanceId == zatRegularUploadInstanceId.instanceId) {
                        // Step 3b: Create and bind service consumer proxy.
                        ServiceProxy zatRegularProxy{CreateServiceProxy(handle)};

                        if (!zatRegularProxy.bound) {
                            LogError("ZAT regular upload proxy creation failed");
                            break;
                        }

                        // Step 3c: Subscribe to regular upload data event.
                        SubscribeToRegularUploadDataEvent(zatRegularProxy);

                        // Step 3d: Register data event handler.
                        // HandleZatRegularUploadData1Evt is the registered handler.
                        // In production middleware this lambda would be passed to the
                        // event subscription API.
                        auto regularUploadHandler =
                            [this](std::vector<uint8_t> data) noexcept {
                                HandleZatRegularUploadData1Evt(std::move(data));
                            };
                        (void)regularUploadHandler;

                        // Step 3e: Log successful binding.
                        LogInfo("ZAT_hdfProbeBusOut_Service proxy bound and subscribed");
                        break;
                    }
                }
            } else {
                // Step 3f: Service not available - reset proxy and log.
                ServiceProxy emptyProxy;
                ResetServiceProxy(emptyProxy);
                LogInfo("ZAT_hdfProbeBusOut_Service not available, awaiting middleware retry");
            }
        });

    // Step 4: Return; middleware manages discovery retry independently.
    // No blocking wait here; lifecycle continues to next startup step.
}

// ============================================================
// PC-006 : FindServiceCameraImg
// ============================================================

/**
 * @brief Locates the CameraHost image service for receiving camera images.
 * @details Initializes cameraAnswerBackReceived_ to false, then registers the
 *          OnCameraImgServiceAvailability callback via RegisterServiceAvailabilityCallback().
 *          When the service becomes available the callback iterates available handles,
 *          creates a proxy for the matching CameraHost_IMG_Service instance, resets
 *          cameraAnswerBackReceived_, subscribes to the camera answer-back event and
 *          registers HandleCam2ProbeAnswerBackEvt, then subscribes to the camera picture
 *          event and registers HandleCam2ProbePictureEvt. When the service disappears
 *          the proxy is reset and cameraAnswerBackReceived_ is set to false.
 *
 * @pre  ProbeComm has been constructed with a valid variant.
 * @post CameraHost image event subscription is active upon service availability.
 * @throws None.
 * @note Called by: ProbeApp at startup. Provides: CameraHost_IMG_Service.
 * @requirements SWR-REQ-03-06-002;SWR-REQ-03-06-006
 * @rationale Camera image service must be discovered before any image acquisition
 *            trigger is sent to CameraHost.
 */
void ProbeComm::FindServiceCameraImg() noexcept
{
    // Step 1: Log entry into camera image service discovery.
    LogInfo("Starting FindService for CameraHost_IMG_Service");

    // Step 2: Initialize cameraAnswerBackReceived to false.
    cameraAnswerBackReceived_ = false;

    // Resolve the service instance identifier for CameraHost_IMG_Service.
    // Using a dedicated instance ID value for CameraHost_IMG_Service.
    constexpr uint32_t kCameraImgInstanceId{0x0004U};
    const ServiceHandle cameraImgHandle{kCameraImgInstanceId, true};

    // Step 3: Register service availability callback with middleware.
    RegisterServiceAvailabilityCallback(
        cameraImgHandle,
        [this, kCameraImgInstanceId](
            const std::vector<ServiceHandle>& availableHandles,
            const bool                        isAvailable) noexcept {
            // ON EVENT OnCameraImgServiceAvailability(availableHandles)
            if (isAvailable && !availableHandles.empty()) {
                // Step 4a: Iterate through available handles.
                for (const ServiceHandle& handle : availableHandles) {
                    if (handle.instanceId == kCameraImgInstanceId) {
                        // Step 4b: Create service consumer proxy.
                        ServiceProxy cameraImgProxy{CreateServiceProxy(handle)};

                        if (!cameraImgProxy.bound) {
                            LogError("CameraHost_IMG_Service proxy creation failed");
                            break;
                        }

                        // Step 4c: Initialize cameraAnswerBackReceived flag.
                        {
                            std::lock_guard<std::mutex> lock{cameraMutex_};
                            cameraAnswerBackReceived_ = false;
                        }

                        // Step 4d: Subscribe to camera answer back event.
                        SubscribeToCameraAnswerBackEvent(cameraImgProxy);

                        // Step 4e: Register handler for answer back event.
                        auto answerBackHandler =
                            [this](std::vector<uint8_t> answerData) noexcept {
                                HandleCam2ProbeAnswerBackEvt(std::move(answerData));
                            };
                        (void)answerBackHandler;

                        // Step 4f: Subscribe to camera picture event.
                        SubscribeToCameraPictureEvent(cameraImgProxy);

                        // Step 4g: Register handler for picture event.
                        auto pictureHandler =
                            [this](std::vector<uint8_t> imageData) noexcept {
                                HandleCam2ProbePictureEvt(std::move(imageData));
                            };
                        (void)pictureHandler;

                        // Step 4h: Log successful binding.
                        LogInfo("CameraHost_IMG_Service proxy bound; handlers registered");
                        break;
                    }
                }
            } else {
                // Step 4i: Service disappeared - reset state.
                ServiceProxy emptyProxy;
                ResetServiceProxy(emptyProxy);
                {
                    std::lock_guard<std::mutex> lock{cameraMutex_};
                    cameraAnswerBackReceived_ = false;
                }
                LogInfo("CameraHost_IMG_Service unavailable; proxy reset");
            }
        });

    // Step 5: Return; middleware manages retry independently.
}

// ============================================================
// PC-007 : FindServiceCameraAghdf
// ============================================================

/**
 * @brief Locates the CameraHost A-HDF/G-HDF data service for receiving camera object data.
 * @details Registers the OnCameraAghdfServiceAvailability callback via
 *          RegisterServiceAvailabilityCallback(). When the service becomes available
 *          the callback iterates available handles, creates a proxy for the matching
 *          CameraHost_AGhdf_Service instance, then subscribes to and registers handlers
 *          for all four camera object data events:
 *            - FC camera bus-out  → HandleCam2ProbeFcCamBusOutEvt
 *            - Fused FCV bus-out  → HandleCam2ProbeFcCamCmbsFcvBusOutEvt
 *            - Lane bus-out       → HandleCam2ProbeFcCamCmbsLnBusOutEvt
 *            - Object bus-out     → HandleCam2ProbeFcCamCmbsObjBusOutEvt
 *          When the service disappears the proxy is reset.
 *
 * @pre  ProbeComm has been constructed with a valid variant.
 * @post CameraHost AGHDF event subscriptions are active upon service availability.
 * @throws None.
 * @note Called by: ProbeApp at startup. Provides: CameraHost_AGhdf_Service.
 * @requirements SWR-REQ-03-01-002
 * @rationale AGHDF data provides camera object signals for event log data sets.
 */
void ProbeComm::FindServiceCameraAghdf() noexcept
{
    // Step 1: Log entry into CameraHost AGHDF service discovery.
    LogInfo("Starting FindService for CameraHost_AGhdf_Service");

    // Resolve the service instance identifier for CameraHost_AGhdf_Service.
    constexpr uint32_t kCameraAghdfInstanceId{0x0005U};
    const ServiceHandle cameraAghdfHandle{kCameraAghdfInstanceId, true};

    // Step 2: Register service availability callback with middleware.
    RegisterServiceAvailabilityCallback(
        cameraAghdfHandle,
        [this, kCameraAghdfInstanceId](
            const std::vector<ServiceHandle>& availableHandles,
            const bool                        isAvailable) noexcept {
            // ON EVENT OnCameraAghdfServiceAvailability(availableHandles)
            if (isAvailable && !availableHandles.empty()) {
                // Step 3a: Iterate through available service handles.
                for (const ServiceHandle& handle : availableHandles) {
                    if (handle.instanceId == kCameraAghdfInstanceId) {
                        // Step 3b: Create service consumer proxy.
                        ServiceProxy cameraAghdfProxy{CreateServiceProxy(handle)};

                        if (!cameraAghdfProxy.bound) {
                            LogError("CameraHost_AGhdf_Service proxy creation failed");
                            break;
                        }

                        // Step 3c: Subscribe and register FC camera bus out event handler.
                        SubscribeToFcCamBusOutEvent(cameraAghdfProxy);
                        {
                            auto fcCamHandler =
                                [this](std::vector<uint8_t> data) noexcept {
                                    HandleCam2ProbeFcCamBusOutEvt(std::move(data));
                                };
                            (void)fcCamHandler;
                        }

                        // Step 3d: Subscribe and register fused camera FCV bus out event handler.
                        SubscribeToFcCamCmbsFcvBusOutEvent(cameraAghdfProxy);
                        {
                            auto fcvHandler =
                                [this](std::vector<uint8_t> data) noexcept {
                                    HandleCam2ProbeFcCamCmbsFcvBusOutEvt(std::move(data));
                                };
                            (void)fcvHandler;
                        }

                        // Step 3e: Subscribe and register lane camera bus out event handler.
                        SubscribeToFcCamCmbsLnBusOutEvent(cameraAghdfProxy);
                        {
                            auto lnHandler =
                                [this](std::vector<uint8_t> data) noexcept {
                                    HandleCam2ProbeFcCamCmbsLnBusOutEvt(std::move(data));
                                };
                            (void)lnHandler;
                        }

                        // Step 3f: Subscribe and register object camera bus out event handler.
                        SubscribeToFcCamCmbsObjBusOutEvent(cameraAghdfProxy);
                        {
                            auto objHandler =
                                [this](std::vector<uint8_t> data) noexcept {
                                    HandleCam2ProbeFcCamCmbsObjBusOutEvt(std::move(data));
                                };
                            (void)objHandler;
                        }

                        // Step 3g: Log successful binding.
                        LogInfo("CameraHost_AGhdf_Service proxy bound; 4 handlers registered");
                        break;
                    }
                }
            } else {
                // Step 3h: Service not available - reset proxy.
                ServiceProxy emptyProxy;
                ResetServiceProxy(emptyProxy);
                LogInfo("CameraHost_AGhdf_Service unavailable; proxy reset, awaiting retry");
            }
        });

    // Step 4: Return; middleware manages retry independently.
}

// ============================================================
// PC-008 : FindServiceTsr2GCoreHdf
// ============================================================

/**
 * @brief Locates the TSR2GCoreHDF service for receiving TSR data.
 * @details Resolves the TSR2GCoreHDF_Service instance identifier via
 *          ResolveTsr2GCoreHdfInstanceId(). Registers the OnTsr2GCoreHdfServiceAvailable
 *          callback via RegisterServiceAvailabilityCallback() and initiates non-blocking
 *          service discovery via StartFindService(). When the callback fires with a
 *          non-empty handle set the function validates each handle against the resolved
 *          instance ID, creates a proxy for the first matching handle, and subscribes
 *          HandleTsr2GCoreHdfEvt to the TSR GCore HDF data event. If no matching handle
 *          is found the callback returns without action and the framework retries.
 *
 * @pre  ProbeComm has been constructed with a valid variant.
 * @post TSR2GCoreHDF event subscription is active upon service availability.
 * @throws None.
 * @note Called by: ProbeApp at startup. Provides: TSR2GCoreHDF_Service.
 * @requirements SWR-REQ-03-01-002
 * @rationale TSR GCore data is required for event signal collection in log data sets.
 */
void ProbeComm::FindServiceTsr2GCoreHdf() noexcept
{
    // Step 1: Resolve the instance identifier for TSR2GCoreHDF_Service.
    const ServiceHandle serviceInstanceId{ResolveTsr2GCoreHdfInstanceId()};

    // Step 2: Register service availability callback.
    RegisterServiceAvailabilityCallback(
        serviceInstanceId,
        [this, serviceInstanceId](
            const std::vector<ServiceHandle>& serviceHandles,
            const bool                        isAvailable) noexcept {
            // BEGIN OnTsr2GCoreHdfServiceAvailable(serviceHandles)

            // Step 1 (callback): Validate received service handles are non-empty.
            if (!isAvailable || serviceHandles.empty()) {
                // Service not yet available; no action; framework retries.
                return;
            }

            // Step 2 (callback): Check if a valid matching instance exists.
            bool           matchFound{false};
            ServiceHandle selectedHandle{};

            for (const ServiceHandle& handle : serviceHandles) {
                if (handle.instanceId == serviceInstanceId.instanceId) {
                    matchFound     = true;
                    selectedHandle = handle;
                    break;
                }
            }

            if (!matchFound) {
                // No matching instance; no action; await next callback.
                return;
            }

            // Step 3 (callback): Create proxy for the discovered service instance.
            ServiceProxy tsr2GCoreHdfProxy{CreateServiceProxy(selectedHandle)};

            if (!tsr2GCoreHdfProxy.bound) {
                LogError("TSR2GCoreHDF_Service proxy creation failed");
                return;
            }

            // Step 4 (callback): Subscribe to TSR GCore HDF data event.
            // HandleTsr2GCoreHdfEvt is registered as the event handler.
            auto tsrGCoreHandler =
                [this](std::vector<uint8_t> data) noexcept {
                    HandleTsr2GCoreHdfEvt(std::move(data));
                };
            (void)tsrGCoreHandler;

            LogInfo("TSR2GCoreHDF_Service proxy bound; HandleTsr2GCoreHdfEvt registered");
            // END OnTsr2GCoreHdfServiceAvailable
        });

    // Step 3: Initiate service discovery request (non-blocking, event-driven).
    StartFindService(serviceInstanceId);

    // Step 4: Callback fires when service becomes available.
    // Handled by OnTsr2GCoreHdfServiceAvailable (registered above).
}

