/// @brief Service tag for hdfCp2ApBusOut_Service.
static constexpr uint32_t kServiceTagHdfCp2Ap{0x000BU};

/// @brief Service tag for SDMAP_Service.
static constexpr uint32_t kServiceTagSdmap{0x000CU};

/// @brief Service tag for probeEventStt_Service.
static constexpr uint32_t kServiceTagProbeEventStt{0x000DU};

/// @brief Service tag for PROBE_TRG_Service.
static constexpr uint32_t kServiceTagProbeTrg{0x000EU};

// ---------------------------------------------------------------------------
// Payload field extraction helpers
// ---------------------------------------------------------------------------

/**
 * @brief Minimum expected byte length of a ZAT trigger payload.
 * @details Layout (little-endian):
 *   [0]      dataUploadRequestFlg  (uint8_t)
 *   [1]      dataTransmissionNum   (uint8_t)
 *   [2..5]   categoryIdentifier    (uint32_t, LE)
 *   [6..9]   logDataStartTime      (int32_t,  LE)
 *   [10..13] logDataEndTime        (int32_t,  LE)
 */
static constexpr std::size_t kTriggerPayloadMinSize{14U};

/**
 * @brief Default past-data retention limit in seconds.
 * @details Matches the system specification default of 10 seconds.
 */
static constexpr uint32_t kDefaultRetentionLimitSec{10U};

/**
 * @brief Extracts the data upload request flag from the raw trigger payload.
 * @param[in] triggerData Raw ZAT trigger payload. Must be >= kTriggerPayloadMinSize bytes.
 * @return uint8_t Extracted flag value.
 */
[[nodiscard]] uint8_t ExtractDataUploadRequestFlag(
    const std::vector<uint8_t>& triggerData) noexcept
{
    return triggerData[0U];
}

/**
 * @brief Extracts the data transmission number from the raw trigger payload.
 * @param[in] triggerData Raw ZAT trigger payload. Must be >= kTriggerPayloadMinSize bytes.
 * @return uint8_t Extracted transmission number.
 */
[[nodiscard]] uint8_t ExtractDataTransmissionNum(
    const std::vector<uint8_t>& triggerData) noexcept
{
    return triggerData[1U];
}

/**
 * @brief Extracts the category identifier (uint32_t, little-endian) from the raw trigger payload.
 * @param[in] triggerData Raw ZAT trigger payload. Must be >= kTriggerPayloadMinSize bytes.
 * @return uint32_t Extracted category identifier.
 */
[[nodiscard]] uint32_t ExtractCategoryIdentifier(
    const std::vector<uint8_t>& triggerData) noexcept
{
    const uint32_t b0{static_cast<uint32_t>(triggerData[2U])};
    const uint32_t b1{static_cast<uint32_t>(triggerData[3U]) << 8U};
    const uint32_t b2{static_cast<uint32_t>(triggerData[4U]) << 16U};
    const uint32_t b3{static_cast<uint32_t>(triggerData[5U]) << 24U};
    return b0 | b1 | b2 | b3;
}

/**
 * @brief Extracts the log data start time (int32_t, little-endian) from the raw trigger payload.
 * @param[in] triggerData Raw ZAT trigger payload. Must be >= kTriggerPayloadMinSize bytes.
 * @return int32_t Extracted log data start time in seconds relative to trigger.
 */
[[nodiscard]] int32_t ExtractLogDataStartTime(
    const std::vector<uint8_t>& triggerData) noexcept
{
    const uint32_t b0{static_cast<uint32_t>(triggerData[6U])};
    const uint32_t b1{static_cast<uint32_t>(triggerData[7U])  << 8U};
    const uint32_t b2{static_cast<uint32_t>(triggerData[8U])  << 16U};
    const uint32_t b3{static_cast<uint32_t>(triggerData[9U])  << 24U};
    const uint32_t raw{b0 | b1 | b2 | b3};
    int32_t result{0};
    static_assert(sizeof(int32_t) == sizeof(uint32_t), "int32_t and uint32_t must be same size");
    // Safe type-punning via memcpy to avoid undefined behaviour.
    std::copy(reinterpret_cast<const uint8_t*>(&raw),
              reinterpret_cast<const uint8_t*>(&raw) + sizeof(int32_t),
              reinterpret_cast<uint8_t*>(&result));
    return result;
}

/**
 * @brief Extracts the log data end time (int32_t, little-endian) from the raw trigger payload.
 * @param[in] triggerData Raw ZAT trigger payload. Must be >= kTriggerPayloadMinSize bytes.
 * @return int32_t Extracted log data end time in seconds relative to trigger.
 */
[[nodiscard]] int32_t ExtractLogDataEndTime(
    const std::vector<uint8_t>& triggerData) noexcept
{
    const uint32_t b0{static_cast<uint32_t>(triggerData[10U])};
    const uint32_t b1{static_cast<uint32_t>(triggerData[11U]) << 8U};
    const uint32_t b2{static_cast<uint32_t>(triggerData[12U]) << 16U};
    const uint32_t b3{static_cast<uint32_t>(triggerData[13U]) << 24U};
    const uint32_t raw{b0 | b1 | b2 | b3};
    int32_t result{0};
    std::copy(reinterpret_cast<const uint8_t*>(&raw),
              reinterpret_cast<const uint8_t*>(&raw) + sizeof(int32_t),
              reinterpret_cast<uint8_t*>(&result));
    return result;
}

/**
 * @brief Returns the configured past-data retention limit in seconds.
 * @details Returns the compile-time default. In a production integration this
 *          would query the variant configuration object.
 * @return uint32_t Retention limit in seconds.
 */
[[nodiscard]] uint32_t GetConfiguredRetentionLimit() noexcept
{
    return kDefaultRetentionLimitSec;
}

