/**
 * @brief Locates the TSR2HDF service for receiving TSR ACore data.
 * @details Implements the TSR HDF Service Discovery algorithm.
 *          Step 1: Resolves the TSR2HDF_Service instance identifier.
 *          Step 2: Registers the OnTsr2HdfServiceAvailable availability callback.
 *          Step 3: Initiates non-blocking service discovery via StartFindService.
 *          Step 4: The availability callback (defined inline as a lambda) fires
 *                  when the service becomes available, validates the handle set,
 *                  selects the matching instance, creates a proxy, and subscribes
 *                  HandleTsr2HdfEvt to the TSR ACore HDF data event.
 *          If the service is not immediately available the middleware retains the
 *          discovery request and fires the callback when the service appears.
 *          If the service disappears after proxy creation the proxy is invalidated
 *          and re-discovery is initiated through the same callback mechanism.
 *          No data is transmitted or processed in this function.
 * @pre  ProbeComm has been constructed with a valid variant.
 * @post TSR2HDF event subscription is active upon service availability.
 * @throws None.
 * @note Called by: ProbeApp at startup. Provides: TSR2HDF_Service.
 * @requirements SWR-REQ-03-01-002
 * @see HandleTsr2HdfEvt
 */
void ProbeComm::FindServiceTsr2Hdf() noexcept
{
    // Step 1: Resolve the instance identifier for TSR2HDF_Service.
    const ServiceInstanceId serviceInstanceId{ResolveTsr2HdfInstanceId()};

    // Step 2: Register service availability callback.
    // The lambda captures serviceInstanceId by value so that the callback can
    // perform instance matching independently of the calling stack frame.
    RegisterServiceAvailabilityCallback(
        kServiceTagTsr2Hdf,
        serviceInstanceId,
        [this, serviceInstanceId](std::vector<ServiceHandle> serviceHandles) noexcept
        {
            // --- OnTsr2HdfServiceAvailable ---

            // Step 1: Validate received service handles are non-empty.
            if (serviceHandles.empty()) {
                // Service not yet available; no action; framework retries.
                return;
            }

            // Step 2: Check if a valid matching instance exists.
            bool         matchFound{false};
            ServiceHandle selectedHandle{};

            for (const ServiceHandle& handle : serviceHandles) {
                if (handle.instanceId == serviceInstanceId.value) {
                    matchFound      = true;
                    selectedHandle  = handle;
                    break;
                }
            }

            if (!matchFound) {
                // No matching instance; no action; await next callback.
                return;
            }

            // Step 3: Create proxy for the discovered service instance.
            ServiceProxy tsr2HdfProxy{CreateServiceProxy(kServiceTagTsr2Hdf, selectedHandle)};

            if (!tsr2HdfProxy.created) {
                // Proxy creation failure — log and await re-discovery.
                LogError("FindServiceTsr2Hdf: proxy creation failed for TSR2HDF_Service");
                return;
            }

            // Step 4: Subscribe to TSR ACore HDF data event.
            tsr2HdfProxy.SubscribeEvent(
                [this](std::vector<uint8_t> data) noexcept {
                    HandleTsr2HdfEvt(std::move(data));
                });
        });

    // Step 3: Initiate service discovery request (non-blocking, event-driven).
    const bool discoveryStarted{StartFindService(kServiceTagTsr2Hdf, serviceInstanceId)};
    if (!discoveryStarted) {
        LogError("FindServiceTsr2Hdf: StartFindService for TSR2HDF_Service returned failure");
    }

    // Step 4: Callback fires when service becomes available.
    // Handled by OnTsr2HdfServiceAvailable (registered above).
}

