/**
 * @brief Locates the SDMAP data service for receiving map data.
 * @details Implements the SDMAP Service Discovery algorithm.
 *          Step 1: Resolves the SDMAP service instance identifier from configuration.
 *          Step 2: Validates the resolved instance identifier; logs and returns on failure.
 *          Step 3: Initiates service discovery for SDMAP_Service via StartFindService.
 *          Step 4: Evaluates the discovery initiation result; logs and returns on failure.
 *          Step 5: Registers the OnSdmapServiceAvailable availability callback so that
 *                  the middleware can notify ProbeComm when the service becomes reachable.
 *          Step 6: Returns; proxy binding is managed asynchronously by the middleware.
 *          No data is transmitted or processed in this function.
 * @pre  ProbeComm has been constructed with a valid variant.
 * @post SDMAP event subscription is active upon service availability.
 * @throws None.
 * @note Called by: ProbeApp at startup. Provides: SDMAP_Service.
 * @requirements SWR-REQ-03-01-002
 * @see HandleSdmapDataEvt
 */
void ProbeComm::FindServiceSdmap() noexcept
{
    // Step 1: Resolve SDMAP service instance identifier from configuration.
    const ServiceInstanceId sdmapInstanceId{ResolveServiceInstanceId(kServiceTagSdmap)};

    // Step 2: Validate resolved instance identifier.
    if (!sdmapInstanceId.isValid()) {
        // Log discovery failure and return; no state change.
        LogError("FindServiceSdmap: SDMAP service instance resolution failed");
        return;
    }

    // Step 3: Initiate service discovery for SDMAP_Service.
    const bool discoveryResult{StartFindService(kServiceTagSdmap, sdmapInstanceId)};

    // Step 4: Evaluate discovery initiation result.
    if (!discoveryResult) {
        // Log and return; middleware will retry independently.
        LogError("FindServiceSdmap: StartFindService for SDMAP returned failure");
        return;
    }

    // Step 5: Register availability callback for SDMAP service handle.
    // OnSdmapServiceAvailable is implemented inline as a capturing lambda.
    RegisterServiceAvailabilityCallback(
        kServiceTagSdmap,
        sdmapInstanceId,
        [this, sdmapInstanceId](std::vector<ServiceHandle> serviceHandles) noexcept
        {
            // --- OnSdmapServiceAvailable ---

            // Validate received service handles are non-empty.
            if (serviceHandles.empty()) {
                return;
            }

            // Check if a valid matching instance exists.
            bool          matchFound{false};
            ServiceHandle selectedHandle{};

            for (const ServiceHandle& handle : serviceHandles) {
                if (handle.instanceId == sdmapInstanceId.value) {
                    matchFound     = true;
                    selectedHandle = handle;
                    break;
                }
            }

            if (!matchFound) {
                return;
            }

            // Create proxy for the discovered service instance.
            ServiceProxy sdmapProxy{CreateServiceProxy(kServiceTagSdmap, selectedHandle)};

            if (!sdmapProxy.created) {
                LogError("FindServiceSdmap: proxy creation failed for SDMAP_Service");
                return;
            }

            // Subscribe to SDMAP data event.
            sdmapProxy.SubscribeEvent(
                [this](std::vector<uint8_t> data) noexcept {
                    HandleSdmapDataEvt(std::move(data));
                });
        });

    // Step 6: Return; proxy binding is managed asynchronously.
    LogInfo("FindServiceSdmap: SDMAP service discovery initiated successfully");
}

// ---------------------------------------------------------------------------
// PC-013 : OfferServiceProbeEventStt
// ---------------------------------------------------------------------------

/**
 * @brief Offers the probeEventStt service to allow ZAT to subscribe for trigger acceptance status.
 * @details Implements the Probe Event Status Service Offer algorithm.
 *          Step 1: Resolves the probeEventStt service instance identifier.
 *          Step 2: Validates the instance identifier; logs and returns on failure.
 *          Step 3: Initialises acceptance status arrays and allowedOverlapTriggerNum_ to
 *                  their default values so that ZAT receives consistent data upon first
 *                  subscription.
 *          Step 4: Instantiates the probeEventStt service skeleton.
 *          Step 5: Validates skeleton creation; logs and returns on failure.
 *          Step 6: Calls OfferService on the skeleton to make the service discoverable.
 *          Step 7: Evaluates the offer result; logs and returns on failure.
 *          Step 8: Logs successful service offering.
 *          The function is bounded and executes once per startup sequence.
 * @pre  ProbeComm has been constructed with a valid variant.
 * @post probeEventStt_Service is offered and ZAT can subscribe.
 * @throws None.
 * @note Called by: ProbeApp at startup. Provides: probeEventStt_Service.
 * @requirements SWR-REQ-03-05-001;SWR-REQ-03-05-003
 */
void ProbeComm::OfferServiceProbeEventStt() noexcept
{
    // Step 1: Resolve probeEventStt service instance identifier.
    const ServiceInstanceId probeEventSttInstanceId{
        ResolveServiceInstanceId(kServiceTagProbeEventStt)};

    // Step 2: Validate instance identifier.
    if (!probeEventSttInstanceId.isValid()) {
        LogError("OfferServiceProbeEventStt: instance resolution failed");
        return;
    }

    // Step 3: Initialize acceptance status arrays to default values.
    // acceptedDataTransmissionNum_ and acceptedCategoryIdentifier_ are scalar
    // members in the header; the pseudocode treats them as arrays of length 2
    // to represent dual-slot acceptance tracking. Both slots are zeroed here.
    acceptedDataTransmissionNum_ = 0x00U;
    acceptedCategoryIdentifier_  = 0x00000000U;
    // allowedOverlapTriggerNum_ is set to the configured overlap limit (1 per spec).
    allowedOverlapTriggerNum_ = 1U;

    // Step 4: Instantiate probeEventStt service skeleton.
    ServiceSkeleton probeEventSttSkeleton{
        CreateServiceSkeleton(kServiceTagProbeEventStt, probeEventSttInstanceId)};

    // Step 5: Validate skeleton creation.
    if (!probeEventSttSkeleton.created) {
        LogError("OfferServiceProbeEventStt: service skeleton creation failed");
        return;
    }

    // Step 6: Offer the service to allow ZAT to discover and subscribe.
    const bool offerResult{probeEventSttSkeleton.OfferService()};

    // Step 7: Evaluate offer result.
    if (!offerResult) {
        LogError("OfferServiceProbeEventStt: OfferService call failed");
        return;
    }

    // Step 8: Log successful service offering.
    LogInfo("OfferServiceProbeEventStt: probeEventStt service offered successfully");
}

