/**
 * @brief Extracts the trigger-stage error code from a Cam2ProbeAnswerBack payload.
 * @details Reads two bytes at kAnswerBackErrorCodeOffset in little-endian order
 *          and assembles them into a uint16_t error code value.
 * @param[in] answerData Raw answer back payload. Must have size >= kAnswerBackMinPayloadSize.
 * @return uint16_t The 16-bit trigger-stage error code.
 * @pre  answerData.size() >= kAnswerBackMinPayloadSize.
 * @post No state is modified.
 * @throws None.
 */
static uint16_t ExtractTriggerErrorCode(const std::vector<uint8_t>& answerData) noexcept
{
    const uint16_t lowByte  = static_cast<uint16_t>(answerData[kAnswerBackErrorCodeOffset]);
    const uint16_t highByte = static_cast<uint16_t>(answerData[kAnswerBackErrorCodeOffset + 1U]);
    return static_cast<uint16_t>(lowByte | static_cast<uint16_t>(highByte << 8U));
}

/**
 * @brief Extracts the PictureSize field from a Cam2ProbePicture payload.
 * @details Reads two bytes at kPictureSizeOffset in little-endian order.
 * @param[in] imageData Raw image data payload. Must have size >= kPictureMinPayloadSize.
 * @return uint16_t The picture size in bytes.
 * @pre  imageData.size() >= kPictureMinPayloadSize.
 * @post No state is modified.
 * @throws None.
 */
static uint16_t ExtractPictureSize(const std::vector<uint8_t>& imageData) noexcept
{
    const uint16_t lowByte  = static_cast<uint16_t>(imageData[kPictureSizeOffset]);
    const uint16_t highByte = static_cast<uint16_t>(imageData[kPictureSizeOffset + 1U]);
    return static_cast<uint16_t>(lowByte | static_cast<uint16_t>(highByte << 8U));
}

/**
 * @brief Extracts the Image_TimeStamp_Sec field from a Cam2ProbePicture payload.
 * @details Reads four bytes at kImageTimestampSecOffset in little-endian order.
 * @param[in] imageData Raw image data payload. Must have size >= kPictureMinPayloadSize.
 * @return uint32_t The timestamp seconds component.
 * @pre  imageData.size() >= kPictureMinPayloadSize.
 * @post No state is modified.
 * @throws None.
 */
static uint32_t ExtractTimestampSec(const std::vector<uint8_t>& imageData) noexcept
{
    const uint32_t b0 = static_cast<uint32_t>(imageData[kImageTimestampSecOffset]);
    const uint32_t b1 = static_cast<uint32_t>(imageData[kImageTimestampSecOffset + 1U]);
    const uint32_t b2 = static_cast<uint32_t>(imageData[kImageTimestampSecOffset + 2U]);
    const uint32_t b3 = static_cast<uint32_t>(imageData[kImageTimestampSecOffset + 3U]);
    return static_cast<uint32_t>(b0 | (b1 << 8U) | (b2 << 16U) | (b3 << 24U));
}

/**
 * @brief Extracts the Image_TimeStamp_MSec field from a Cam2ProbePicture payload.
 * @details Reads four bytes at kImageTimestampMsecOffset in little-endian order.
 * @param[in] imageData Raw image data payload. Must have size >= kPictureMinPayloadSize.
 * @return uint32_t The timestamp milliseconds component.
 * @pre  imageData.size() >= kPictureMinPayloadSize.
 * @post No state is modified.
 * @throws None.
 */
static uint32_t ExtractTimestampMsec(const std::vector<uint8_t>& imageData) noexcept
{
    const uint32_t b0 = static_cast<uint32_t>(imageData[kImageTimestampMsecOffset]);
    const uint32_t b1 = static_cast<uint32_t>(imageData[kImageTimestampMsecOffset + 1U]);
    const uint32_t b2 = static_cast<uint32_t>(imageData[kImageTimestampMsecOffset + 2U]);
    const uint32_t b3 = static_cast<uint32_t>(imageData[kImageTimestampMsecOffset + 3U]);
    return static_cast<uint32_t>(b0 | (b1 << 8U) | (b2 << 16U) | (b3 << 24U));
}

/**
 * @brief Extracts the ImageFrameCounter field from a Cam2ProbePicture payload.
 * @details Reads one byte at kFrameCounterOffset.
 * @param[in] imageData Raw image data payload. Must have size >= kPictureMinPayloadSize.
 * @return uint8_t The frame counter value.
 * @pre  imageData.size() >= kPictureMinPayloadSize.
 * @post No state is modified.
 * @throws None.
 */
static uint8_t ExtractFrameCounter(const std::vector<uint8_t>& imageData) noexcept
{
    return imageData[kFrameCounterOffset];
}

