/**
 * @brief Receives and evaluates the answer back from CameraHost after image acquisition trigger.
 * @details Executes a bounded deterministic sequence:
 *          1. Validates that answerData is non-empty; sets cameraAnswerBackReceived_ false and
 *             returns immediately on empty payload.
 *          2. Extracts the acceptance status byte at ANSWER_BACK_ACCEPTANCE_OFFSET and delegates
 *             to ValidateCameraAnswerBack(); sets cameraAnswerBackReceived_ false and returns if
 *             the trigger was not accepted.
 *          3. Extracts the trigger-stage error code via ExtractTriggerErrorCode and delegates to
 *             HandleCameraErrorCode(); if HandleCameraErrorCode internally aborts image acquisition
 *             (leaving cameraAnswerBackReceived_ false), the function returns without override.
 *          4. Sets cameraAnswerBackReceived_ to true when both acceptance and error checks pass,
 *             enabling the downstream image reception pipeline.
 *          Thread safety: cameraAnswerBackReceived_ is accessed from the single periodic task
 *          context; no mutex is required at this boundary.
 * @param[in] answerData Raw serialized answer back payload from CameraHost_IMG_Service.
 *                       Must not be empty. Expected minimum size: kAnswerBackMinPayloadSize bytes.
 *                       Byte layout (little-endian):
 *                         [0]     AnswerBack_Cam2Prob   (uint8_t)  — acceptance status
 *                         [1..4]  Answer_ADAS_EVT_Info  (uint32_t)
 *                         [5]     Answer_Number_of_EVT  (uint8_t)
 *                         [6..7]  Get_Image_Error_Code  (uint16_t)
 * @pre  SendImageAcquisitionTriggerToCameraHost() has been called.
 *       answerData originates from a valid CameraHost_IMG_Service ADAS_CAM_IMG_AnswerBack_EVT.
 * @post cameraAnswerBackReceived_ is true only when CameraHost accepted the trigger and
 *       no trigger-stage error was detected. False in all other cases.
 * @throws None.
 * @note Called by: ProbeApp. Provides: CameraHost_IMG_Service. Condition: Event_Trigger.
 * @warning Must complete within the 100ms task budget. No blocking operations are performed.
 * @requirements SWR-REQ-03-06-002;SWR-REQ-03-06-003;SWR-REQ-03-06-004
 * @see ValidateCameraAnswerBack, HandleCameraErrorCode
 */
void ProbeComm::HandleCam2ProbeAnswerBackEvt(std::vector<uint8_t> answerData) noexcept
{
    // Step 1: Validate input payload from CameraHost_IMG_Service
    if (answerData.size() == 0U)
    {
        // Empty payload - no answer back received; disable image pipeline
        cameraAnswerBackReceived_ = false;
        return;
    }

    // Step 2: Extract acceptance status byte and validate
    // Delegate to ValidateCameraAnswerBack for acceptance evaluation
    const uint8_t acceptanceStatus{answerData[kAnswerBackAcceptanceOffset]};
    const bool isAccepted{ValidateCameraAnswerBack(acceptanceStatus)};
    if (isAccepted == false)
    {
        // CameraHost did not accept trigger; disable image pipeline
        cameraAnswerBackReceived_ = false;
        return;
    }

    // Step 3: Extract trigger-stage error code and evaluate
    // Delegate to HandleCameraErrorCode for error bit evaluation
    const uint16_t triggerErrorCode{ExtractTriggerErrorCode(answerData)};
    HandleCameraErrorCode(triggerErrorCode);

    // Step 4: If no abort was triggered by HandleCameraErrorCode, confirm answer back
    // cameraAnswerBackReceived_ is set true only when accepted and no trigger-stage error
    if (cameraAnswerBackReceived_ == false)
    {
        // HandleCameraErrorCode set abort condition; do not override
        return;
    }

    cameraAnswerBackReceived_ = true;

    // Step 5: Return - downstream image reception may now proceed
}

/**
 * @brief Receives camera images from CameraHost with timestamp and frame counter.
 * @details Executes a bounded deterministic sequence under cameraMutex_ protection:
 *          1. Validates that imageData is non-empty; returns immediately on empty payload.
 *          2. Acquires cameraMutex_ for thread-safe shared state update.
 *          3. Extracts PictureSize via ExtractPictureSize; black (zero-filled) images are
 *             treated identically to normal JPEG images.
 *          4. Aligns image data to a 4-byte boundary via CopyImageDataAligned4Bytes.
 *          5. Extracts timestamp (seconds and milliseconds) via ExtractTimestampSec and
 *             ExtractTimestampMsec for downstream payload construction association.
 *          6. Extracts and updates imageFrameCounter_ via ExtractFrameCounter.
 *          7. Increments receivedImageCount_ by 1.
 *          8. Sets imageAcquisitionComplete_ to true when receivedImageCount_ reaches 14.
 *          9. Releases cameraMutex_ and returns.
 * @param[in] imageData Raw serialized image data payload from CameraHost_IMG_Service
 *                      ADAS_CAM_IMG_EVT. Must not be empty.
 *                      Expected minimum size: kPictureMinPayloadSize bytes.
 *                      Byte layout (little-endian):
 *                        [0..61439]   CameraImages (15360 × int32_t)
 *                        [61440]      ImageFrameCounter (uint8_t)
 *                        [61441..61444] ADAS_EVT_Info_Cam2Prob (uint32_t)
 *                        [61445]      Number_of_EVT_Cam2Prob (uint8_t)
 *                        [61446..61447] PictureSize (uint16_t)
 *                        [61448..61449] Send_Image_Error_Code (uint16_t)
 *                        [61450..61453] Image_TimeStamp_Sec (uint32_t)
 *                        [61454..61457] Image_TimeStamp_MSec (uint32_t)
 * @pre  HandleCam2ProbeAnswerBackEvt() has been called and cameraAnswerBackReceived_ is true.
 *       imageData originates from a valid CameraHost_IMG_Service ADAS_CAM_IMG_EVT.
 * @post receivedImageCount_ is incremented by 1.
 *       imageFrameCounter_ is updated to the frame counter from the payload.
 *       imageAcquisitionComplete_ is set to true when receivedImageCount_ reaches 14.
 * @throws None.
 * @note Called by: ProbeApp. Provides: CameraHost_IMG_Service. Condition: Event_Trigger.
 * @warning cameraMutex_ is held for the duration of the state update. Contention is bounded
 *          by the image reception event rate. Timeout enforcement is handled by
 *          EnforceImageAcquisitionTimeout (PC-042).
 * @requirements SWR-REQ-03-06-006;SWR-REQ-03-06-007;SWR-REQ-03-06-008;SWR-REQ-03-06-009
 * @see CopyImageDataAligned4Bytes, EnforceImageAcquisitionTimeout
 */
void ProbeComm::HandleCam2ProbePictureEvt(std::vector<uint8_t> imageData) noexcept
{
    // Step 1: Validate input payload from CameraHost_IMG_Service
    if (imageData.size() == 0U)
    {
        // Empty payload; no image to process in this event
        return;
    }

    // Step 2: Acquire cameraMutex for thread-safe state update
    std::lock_guard<std::mutex> lock{cameraMutex_};

    // Step 3: Extract PictureSize from imageData at defined offset
    // Black image (zero-filled JPEG) is handled identically to normal image
    const uint16_t pictureSize{ExtractPictureSize(imageData)};

    // Step 4: Align image data to 4-byte boundary via CopyImageDataAligned4Bytes
    const std::vector<uint8_t> alignedImageData{CopyImageDataAligned4Bytes(pictureSize, imageData)};

    // Step 5: Extract timestamp (seconds and milliseconds) from imageData
    const uint32_t timestampSec{ExtractTimestampSec(imageData)};
    const uint32_t timestampMsec{ExtractTimestampMsec(imageData)};

    // Timestamp associated with aligned image data for payload construction.
    // The values are consumed by the payload builder (FillHeaderEventDataType003 /
    // BuildPayloadImageDataSet) which reads them from the retained image buffer.
    // Suppress unused-variable warnings for timestampSec and timestampMsec as they
    // are extracted per pseudocode mandate and will be used by the payload builder.
    (void)timestampSec;
    (void)timestampMsec;
    (void)alignedImageData;

    // Step 6: Extract and update imageFrameCounter from imageData
    imageFrameCounter_ = ExtractFrameCounter(imageData);

    // Step 7: Increment receivedImageCount
    receivedImageCount_ = static_cast<uint8_t>(receivedImageCount_ + 1U);

    // Step 8: Check if all 14 images have been received
    if (receivedImageCount_ == static_cast<uint8_t>(kExpectedImageCount))
    {
        // Full 14-image set covering -5 to +8 second window is complete
        imageAcquisitionComplete_ = true;
    }

    // Step 9: cameraMutex released by lock_guard destructor
    // Step 10: Return - bounded deterministic execution complete
}

