// ===========================================================================
// PC-028 — HandleResultBdpEvt
// ===========================================================================

/**
 * @brief Receives and processes the BDP upload completion result code from DAQ.
 * @details This handler is triggered by the arrival of a RESULT_BDP_EVT event from
 *          the CORE_DAQ_devEvent_Service. The function receives a single input,
 *          resultCode, of type uint16_t. It evaluates resultCode against the known
 *          success value (kBdpResultCodeSuccess == 0x0000). If the result code
 *          indicates successful acceptance by DAQ, the function calls
 *          DeleteEventDataAfterDaqSuccess to purge the development event data
 *          associated with this transmission from the active process memory.
 *          If the result code does not indicate success, no deletion is performed
 *          and no retry is initiated within this function; retry logic is managed
 *          separately by the BDP transmit retry path (EnforceBdpTransmitRetry /
 *          AbortEventDataTransmissionOnRetryExhaustion). The function is deterministic,
 *          bounded in execution, and performs no blocking operations. It does not
 *          modify retry counters directly; it only acts on a confirmed success outcome
 *          by triggering memory release.
 * @param[in] resultCode BDP upload result code from DAQ.
 *                       Valid range: [0x0000, 0xFFFF]. 0x0000 indicates success.
 * @pre  TransmitBdpDataToDAQ() has been called and a response is pending.
 * @post Event data is deleted on success via DeleteEventDataAfterDaqSuccess().
 *       No state change occurs for non-success result codes within this function.
 * @throws None.
 * @note Called by: ProbeApp. Provides: CORE_DAQ_devEvent_Service. Condition: Event_Trigger.
 *       Retry and abort logic for non-success codes is handled externally by
 *       EnforceBdpTransmitRetry() and AbortEventDataTransmissionOnRetryExhaustion().
 * @warning Do not add retry logic inside this function; it violates single-responsibility.
 * @see DeleteEventDataAfterDaqSuccess
 * @see EnforceBdpTransmitRetry
 * @see AbortEventDataTransmissionOnRetryExhaustion
 * @requirements SWR-REQ-03-10-001
 * @rationale Result code processing ensures reliable delivery confirmation before
 *            event data is released from memory, preventing premature buffer reuse.
 */
void ProbeComm::HandleResultBdpEvt(uint16_t resultCode) noexcept
{
    // Step 1: Validate the received result code is within known value range.
    if (resultCode == kBdpResultCodeSuccess)
    {
        // Step 2: Invoke memory cleanup for the confirmed-successful event data.
        DeleteEventDataAfterDaqSuccess();
    }
    // Step 3: No action on non-success; retry and abort paths handled externally.
    // No-op: state is preserved for retry handling by EnforceBdpTransmitRetry /
    // AbortEventDataTransmissionOnRetryExhaustion.

    // Step 4: Function returns; no further state change within this unit.
}

// ===========================================================================
// PC-029 — ValidateTriggerUploadRequestFlag
// ===========================================================================

/**
 * @brief Checks if the data upload request flag is non-zero to determine a valid trigger.
 * @details This pure predicate receives flag as a uint8_t argument and evaluates whether
 *          the value is non-zero. If the value is 1 (Probe trigger), 2 (GEDR trigger),
 *          or 3 (both), the function returns true indicating a valid event trigger has
 *          been received. If the value is 0, the function returns false, indicating no
 *          trigger condition. No state is modified by this function; it is a pure predicate
 *          used by HandleAdasAcoreTriggerEvt to gate downstream trigger processing.
 *          Execution is fully bounded and deterministic with O(1) complexity.
 *          Any non-zero value outside the defined range (1, 2, 3) still evaluates as true,
 *          which is the intended safe default since the flag is treated as a presence
 *          indicator. The calling function HandleAdasAcoreTriggerEvt is responsible for
 *          further validation of the specific flag value to route Probe-only versus
 *          GEDR-only versus both-path processing.
 * @param[in] flag Upload request flag value from ZAT trigger data.
 *                 Valid range: [0x00, 0xFF]. Non-zero indicates valid request.
 *                 Defined values: 0x00 = no request, 0x01 = Probe, 0x02 = GEDR, 0x03 = both.
 * @return bool Indicates whether the upload request flag is valid.
 * @retval true  Flag is non-zero; trigger is a valid upload request.
 * @retval false Flag is zero; trigger should be ignored.
 * @pre  flag has been extracted from a valid ZAT trigger data vector.
 * @post No state is modified.
 * @throws None.
 * @note Called by: ProbeComm. Cyclic: 100ms.
 *       dataUploadRequestFlg_ private member holds the current upload request flag
 *       for consistency cross-reference; this function operates on the provided argument.
 * @see HandleAdasAcoreTriggerEvt
 * @requirements SWR-REQ-03-02-002;SWR-REQ-03-003
 * @rationale Flag validation prevents spurious event processing from zero-value triggers,
 *            ensuring only intentional ZAT trigger events initiate event data collection.
 */
[[nodiscard]] bool ProbeComm::ValidateTriggerUploadRequestFlag(uint8_t flag) const noexcept
{
    // Step 1: Receive input flag of type uint8_t.
    // Step 2: Evaluate flag value.
    if (flag != static_cast<uint8_t>(0U))
    {
        // Step 3: Non-zero value means a valid trigger is present (Probe=1, GEDR=2, Both=3).
        return true;
    }
    else
    {
        // Step 4: Zero means no active trigger; suppress downstream processing.
        return false;
    }
}

// ===========================================================================
// PC-030 — CheckSameCategoryLimit
// ===========================================================================

/**
 * @brief Validates whether the acceptance counter for a category has reached the configurable limit.
 * @details Receives categoryId of type uint32_t. Declares a local variable currentCount
 *          of type uint32_t initialized to zero. Performs a lookup in categoryTriggerCountMap_
 *          for the given categoryId. If the categoryId is not found in the map, currentCount
 *          remains zero, meaning the trigger is below the limit and the function returns false.
 *          If the categoryId is found, the stored count is assigned to currentCount and compared
 *          against sameCategoryLimitPerDC_. If currentCount is greater than or equal to
 *          sameCategoryLimitPerDC_, the function returns true, signaling that the trigger must
 *          be rejected. If currentCount is less than sameCategoryLimitPerDC_, the function
 *          returns false, signaling that acceptance is permitted. The function does not modify
 *          categoryTriggerCountMap_; counter increment upon acceptance is handled by the
 *          calling context in HandleAdasAcoreTriggerEvt. Execution is deterministic and
 *          O(log n) bounded by the map lookup.
 * @param[in] categoryId Category identifier to check.
 *                       Valid range: [0x00000000, 0xFFFFFFFF].
 * @return bool Indicates whether the per-category limit has been reached.
 * @retval true  Category acceptance count has reached or exceeded sameCategoryLimitPerDC_.
 * @retval false Category acceptance count is below the limit; trigger may be accepted.
 * @pre  categoryTriggerCountMap_ is initialized. sameCategoryLimitPerDC_ > 0.
 * @post No state is modified.
 * @throws None.
 * @note Called by: ProbeComm. Cyclic: 100ms.
 *       If sameCategoryLimitPerDC_ is zero due to a configuration error, the function
 *       returns true for any lookup (0 >= 0), effectively rejecting all probe triggers.
 *       This edge case must be addressed at configuration validation during initialization.
 * @warning If sameCategoryLimitPerDC_ is zero, all triggers will be rejected.
 *          Validate configuration at startup to prevent this condition.
 * @see HandleAdasAcoreTriggerEvt
 * @see ResetCategoryCounterOnNewDriveCycle
 * @requirements SWR-REQ-03-12-001;SWR-REQ-03-12-002;SWR-REQ-03-12-005;SWR-REQ-03-12-006
 * @rationale Per-category limits prevent over-collection of similar events within a
 *            drive cycle, ensuring fair distribution of storage resources across categories.
 */
[[nodiscard]] bool ProbeComm::CheckSameCategoryLimit(uint32_t categoryId) const noexcept
{
    // Step 1: Receive categoryId : uint32_t.
    // Step 2: Attempt lookup of categoryId in categoryTriggerCountMap.
    uint32_t currentCount{0U};

    const auto it = categoryTriggerCountMap_.find(categoryId);
    if (it != categoryTriggerCountMap_.cend())
    {
        // Category found: assign stored acceptance count.
        currentCount = it->second;
    }
    else
    {
        // Step 3: Category not seen in this driving cycle; count starts at zero.
        currentCount = 0U;
    }

    // Step 4: Compare count against configurable limit.
    if (currentCount >= sameCategoryLimitPerDC_)
    {
        // Limit reached or exceeded: trigger must be rejected.
        return true;
    }
    else
    {
        // Below limit: trigger may be accepted.
        return false;
    }
}

// ===========================================================================
// PC-031 — CheckOverlapTriggerLimit
// ===========================================================================

/**
 * @brief Validates whether the active event process count exceeds the allowed overlap limit.
 * @details Invoked upon receipt of a new event trigger. Reads activeEventProcessCount_
 *          and allowedOverlapTriggerNum_ from the ProbeComm instance's private members.
 *          If activeEventProcessCount_ is greater than or equal to allowedOverlapTriggerNum_,
 *          the function returns true, indicating that no additional parallel event processing
 *          can be initiated. If activeEventProcessCount_ is strictly less than
 *          allowedOverlapTriggerNum_, the function returns false, indicating that a new
 *          parallel event data generation process may begin. The function does not modify
 *          activeEventProcessCount_; incrementing and decrementing this counter is managed
 *          by the trigger acceptance and event completion paths respectively. Execution is
 *          deterministic, O(1), and fully bounded.
 * @return bool Indicates whether the overlap trigger limit has been reached.
 * @retval true  activeEventProcessCount_ >= allowedOverlapTriggerNum_; new trigger rejected.
 * @retval false activeEventProcessCount_ < allowedOverlapTriggerNum_; new trigger may proceed.
 * @pre  allowedOverlapTriggerNum_ > 0.
 * @post No state is modified.
 * @throws None.
 * @note Called by: ProbeComm. Condition: Event_Trigger.
 *       If allowedOverlapTriggerNum_ is zero due to a configuration error, the function
 *       always returns true, blocking all event trigger acceptance. Validate configuration
 *       at startup to prevent this condition.
 * @warning If allowedOverlapTriggerNum_ is zero, all triggers will be rejected.
 *          Validate configuration at startup to prevent this condition.
 * @see HandleAdasAcoreTriggerEvt
 * @see DeleteEventDataAfterDaqSuccess
 * @see DeleteEventDataOnRetryExhaustion
 * @requirements SWR-REQ-03-04-003;SWR-REQ-03-04-004
 * @rationale Overlap limit prevents resource exhaustion from simultaneous event processing,
 *            ensuring the system can always accept new triggers after active events complete.
 */
[[nodiscard]] bool ProbeComm::CheckOverlapTriggerLimit() const noexcept
{
    // Step 1: Read current values of activeEventProcessCount_ and allowedOverlapTriggerNum_.
    // Step 2: Compare active count against allowed overlap limit.
    if (activeEventProcessCount_ >= allowedOverlapTriggerNum_)
    {
        // Step 3: Overlap limit reached; incoming trigger must be rejected.
        return true;
    }
    else
    {
        // Step 4: Capacity available; trigger may be accepted.
        return false;
    }
}

// ===========================================================================
// PC-032 — ValidateLogStartTimeClamping
// ===========================================================================

/**
 * @brief Clamps log data start time to the negative of past data retention setting when exceeded.
 * @details Accepts the raw log data start time (a negative offset in seconds from trigger
 *          point) and the configured past data retention limit. The function first computes
 *          the absolute value of startTime into the local variable absStartTime. It then
 *          checks whether absStartTime exceeds static_cast<int32_t>(retentionLimit). If
 *          absStartTime is greater than static_cast<int32_t>(retentionLimit), the function
 *          sets effectiveLogStartTime_ to the negative of the retention limit value using
 *          -static_cast<int32_t>(retentionLimit). If absStartTime is within the retention
 *          limit, effectiveLogStartTime_ is assigned unchanged from the input. The result
 *          is stored in the private member effectiveLogStartTime_ and also returned to the
 *          caller. This ensures the log data window never reaches beyond available buffer
 *          history, preventing access violations and undefined data states. The function is
 *          deterministic, performs no dynamic allocation, and executes within a single
 *          bounded evaluation.
 * @param[in] startTime    Log data start time in seconds relative to trigger. Range: [INT32_MIN, 0].
 * @param[in] retentionLimit Past data retention limit in seconds. Range: [0, INT32_MAX].
 * @return int32_t Clamped log data start time in seconds.
 * @retval -static_cast<int32_t>(retentionLimit) When startTime exceeds the retention limit.
 * @retval startTime When startTime is within the retention limit.
 * @pre  retentionLimit > 0. startTime <= 0.
 * @post effectiveLogStartTime_ is updated with the clamped value.
 * @throws None.
 * @note Called by: ProbeComm. Condition: Event_Trigger.
 *       If retentionLimit is zero, effectiveLogStartTime_ is clamped to zero regardless
 *       of input, which is a safe and deterministic default.
 *       If startTime is provided as a positive value (semantically invalid), the absolute
 *       value computation still clamps correctly; no special error path is required.
 * @see ValidateGedrLogStartTime
 * @requirements SWR-REQ-03-02-003;SWR-REQ-03-17-007
 * @rationale Clamping prevents requesting data older than the retention buffer can provide,
 *            avoiding access violations and undefined data states in the log data set.
 */
[[nodiscard]] int32_t ProbeComm::ValidateLogStartTimeClamping(
    int32_t startTime,
    uint32_t retentionLimit) noexcept
{
    // Step 1: Compute the absolute value of the incoming start time.
    // std::abs is used for int32_t; result is always non-negative.
    const int32_t absStartTime{(startTime < static_cast<int32_t>(0)) ? -startTime : startTime};

    // Step 2: Compare absolute start time with the past data retention limit.
    if (absStartTime > static_cast<int32_t>(retentionLimit))
    {
        // Step 3a: Clamp to negative retention limit.
        effectiveLogStartTime_ = -static_cast<int32_t>(retentionLimit);
    }
    else
    {
        // Step 3b: Accept the received start time as-is.
        effectiveLogStartTime_ = startTime;
    }

    // Step 4: Return the validated effective start time.
    return effectiveLogStartTime_;
}

