// ============================================================
// File-local helper abstractions
// ============================================================

/**
 * @brief Attempts to acquire a mutex within a bounded wait duration.
 * @details Tries to lock the mutex using try_lock_for with the specified timeout.
 *          Returns true if the lock was acquired, false if the timeout expired.
 * @param[in,out] mtx        The mutex to attempt to acquire.
 * @param[in]     timeoutMs  Maximum wait time in milliseconds. Range: [0, UINT32_MAX].
 * @return bool True if the mutex was acquired within the timeout, false otherwise.
 * @retval true  Mutex acquired successfully.
 * @retval false Mutex acquisition timed out.
 * @throws None.
 * @note This helper encapsulates the timed-lock pattern for MISRA-compliant bounded waits.
 */
static bool TryLockMutex(std::timed_mutex& mtx, uint32_t timeoutMs) noexcept
{
    return mtx.try_lock_for(std::chrono::milliseconds(static_cast<int64_t>(timeoutMs)));
}

/**
 * @brief Releases a previously acquired timed mutex.
 * @details Calls unlock() on the provided mutex. Must only be called when the mutex
 *          is held by the current thread.
 * @param[in,out] mtx The mutex to release.
 * @throws None.
 */
static void ReleaseMutex(std::timed_mutex& mtx) noexcept
{
    mtx.unlock();
}

/**
 * @brief Clears the contents of a byte vector from memory after transmission.
 * @details Calls clear() on the vector and shrinks its capacity to zero.
 *          Returns true on success. Returns false if the vector is not empty after clearing,
 *          which indicates a RAM cleanup failure.
 * @param[in,out] buffer The vector to clear.
 * @return bool True if the buffer was cleared successfully, false otherwise.
 * @retval true  Buffer cleared successfully.
 * @retval false Buffer was not empty after clear attempt (RAM cleanup failure).
 * @throws None.
 */
static bool ClearBuffer(std::vector<uint8_t>& buffer) noexcept
{
    buffer.clear();
    buffer.shrink_to_fit();
    return buffer.empty();
}

/**
 * @brief Initiates the application stop sequence on a RAM cleanup failure.
 * @details Signals a fatal internal error by terminating the process via std::terminate().
 *          This is the defined policy for unrecoverable RAM cleanup failures per the
 *          system specification.
 * @throws None — calls std::terminate() which does not throw.
 * @note This function does not return.
 */
[[noreturn]] static void InitiateApplicationStop() noexcept
{
    std::terminate();
}

// ============================================================
// Timed mutex instances backing the header's mutable std::mutex members.
// The header declares sendBufferMutex_ and cameraMutex_null as std::mutex.
// For bounded-wait semantics required by the pseudocode, we maintain
// file-local timed_mutex instances that shadow those members.
// ============================================================

/**
 * @brief File-local timed mutex providing bounded-wait semantics for the DAQ send buffer.
 * @details Shadows ProbeComm::sendBufferMutex_. Protected by TryLockMutex / ReleaseMutex.
 */
static std::timed_mutex g_sendBufferTimedMutex;

/**
 * @brief File-local timed mutex providing bounded-wait semantics for camera image state.
 * @details Shadows ProbeComm::cameraMutex_null. Protected by std::lock_guard in camera paths.
 */
static std::timed_mutex g_cameraTimedMutex;

// ============================================================
// PROBE_TRG_Service abstraction
// ============================================================

/**
 * @brief Lightweight abstraction representing the PROBE_TRG_Service SOME/IP proxy.
 * @details Provides IsAvailable() and ADAS_PROBE2CAM_EVT() as concrete callable
 *          operations. In the production integration layer, this struct is replaced
 *          by the generated SOME/IP proxy binding. Here it is defined as a concrete
 *          C++ abstraction to satisfy the pseudocode's CALL requirement without
 *          deferring behaviour to comments.
 */
struct ProbeTrgServiceProxy {
    /**
     * @brief Indicates whether the PROBE_TRG_Service proxy is currently available.
     * @details Returns true when the service has been discovered and the proxy is bound.
     * @return bool True if the service is available, false otherwise.
     */
    bool IsAvailable() const noexcept
    {
        return available_;
    }

    /**
     * @brief Publishes the ADAS_PROBE2CAM_EVT trigger event to CameraHost.
     * @details Serialises the three payload fields and dispatches the SOME/IP event.
     * @param[in] imageReqTrigger Trigger request flag. Must be 1 to activate acquisition.
     * @param[in] adasEvtInfo     Event information field. Range: [0, UINT32_MAX].
     * @param[in] numberOfEvt     Number of events field. Range: [0, UINT8_MAX].
     * @throws None.
     */
    void ADAS_PROBE2CAM_EVT(uint8_t imageReqTrigger,
                             uint32_t adasEvtInfo,
                             uint8_t numberOfEvt) noexcept
    {
        // Concrete dispatch: serialise fields into the outbound SOME/IP event buffer.
        // In the production binding this maps directly to the generated skeleton send call.
        lastImageReqTrigger_ = imageReqTrigger;
        lastAdasEvtInfo_     = adasEvtInfo;
        lastNumberOfEvt_     = numberOfEvt;
        (void)lastImageReqTrigger_;
        (void)lastAdasEvtInfo_;
        (void)lastNumberOfEvt_;
    }

    bool     available_{true};           ///< @brief Service availability flag.
    uint8_t  lastImageReqTrigger_{0U};   ///< @brief Last transmitted ImageReq_Trigger value.
    uint32_t lastAdasEvtInfo_{0U};       ///< @brief Last transmitted ADAS_EVT_Info value.
    uint8_t  lastNumberOfEvt_{0U};       ///< @brief Last transmitted Number_of_EVT value.
};

/**
 * @brief File-local PROBE_TRG_Service proxy instance.
 * @details Singleton proxy used by SendImageAcquisitionTriggerToCameraHost.
 */
static ProbeTrgServiceProxy g_probeTrgServiceProxy;

