// ============================================================
// PC-033 — ValidateLogEndTimeClamping
// ============================================================

/**
 * @brief Clamps log data end time to +83 when the received value exceeds the limit.
 * @details Implements the Log End Time Upper Boundary Enforcement algorithm.
 *          Defines the local constant MAX_LOG_END_TIME as 83. Evaluates whether
 *          endTime exceeds MAX_LOG_END_TIME. If so, effectiveLogEndTime_ is set to
 *          MAX_LOG_END_TIME. Otherwise effectiveLogEndTime_ is set to endTime.
 *          The validated value is returned to the caller.
 *
 *          This function is deterministic, performs no dynamic allocation, and
 *          completes within a single bounded evaluation cycle.
 *
 * @param[in] endTime Log data end time in seconds relative to trigger.
 *                    Range: [INT32_MIN, INT32_MAX]. Values > 83 are clamped.
 * @return int32_t Clamped log data end time in seconds.
 * @retval 83       When endTime > 83.
 * @retval endTime  When endTime <= 83.
 * @pre  None.
 * @post effectiveLogEndTime_ holds the clamped value.
 * @throws None.
 * @note Called by: ProbeComm. Condition: Event_Trigger.
 * @requirements SWR-REQ-03-02-004
 * @rationale +83 seconds is the maximum future data window; values beyond this are invalid.
 * @see ValidateLogStartTimeClamping
 */
int32_t ProbeComm::ValidateLogEndTimeClamping(int32_t endTime) noexcept
{
    // Step 1: Define the maximum allowable log end time
    const int32_t MAX_LOG_END_TIME{83};

    // Step 2 / Step 3: Evaluate whether the received end time exceeds the maximum
    if (endTime > MAX_LOG_END_TIME)
    {
        // Step 3a: Clamp to the maximum allowed end time
        effectiveLogEndTime_ = MAX_LOG_END_TIME;
    }
    else
    {
        // Step 3b: Accept the received end time as-is
        effectiveLogEndTime_ = endTime;
    }

    // Step 4: Return the validated effective end time
    return effectiveLogEndTime_;
}

// ============================================================
// PC-034 — SendContinualShortDataCyclic100ms
// ============================================================

/**
 * @brief Transmits short-cycle steady-state data to DAQ via SOME/IP UDP at 100ms intervals.
 * @details Implements the 100ms Cyclic Steady-State Short Data Transmission algorithm.
 *          Evaluates DAQ session state via SuppressDataBeforeDaqEstablished(). If the
 *          session is not established, returns immediately. Acquires sendBufferMutex via
 *          TryLockMutex with MAX_MUTEX_WAIT_MS. Validates payload is non-empty. Invokes
 *          SendDaqFireForgetMethod with CLIENT_ID_CONTINUAL_SHORT and PDU_ID_CONTINUAL_SHORT.
 *          Calls ClearBuffer to release the payload. If ClearBuffer fails, calls
 *          ReleaseMutex then InitiateApplicationStop. Otherwise releases the mutex.
 *
 * @param[in] payload Serialized short-cycle steady-state data. Must not be empty.
 *                    Maximum size defined by DAQ SOME/IP UDP MTU (1200 bytes).
 * @pre  FindServiceDaqContinual() has been called. daqCommunicationEstablished_ is true.
 * @post Payload is transmitted to DAQ if communication is established.
 * @throws None.
 * @note Called by: ProbeApp. Provides: CORE_DAQ_continual_Service. Cyclic: 100ms.
 * @warning Must complete within the 100ms task budget.
 * @requirements SWR-REQ-01-001;SWR-REQ-01-06-001;SWR-REQ-01-05-001
 * @see SendDaqFireForgetMethod, SuppressDataBeforeDaqEstablished
 */
void ProbeComm::SendContinualShortDataCyclic100ms(std::vector<uint8_t> payload) noexcept
{
    // Step 1: Check if DAQ SOME/IP communication is established
    if (SuppressDataBeforeDaqEstablished() == true)
    {
        // Step 2a: Session not yet established, suppress transmission
        return;
    }

    // Step 3: Acquire send buffer mutex with bounded wait
    const bool lockResult{TryLockMutex(g_sendBufferTimedMutex, MAX_MUTEX_WAIT_MS)};
    if (lockResult == false)
    {
        // Step 3a: Mutex acquisition failed, skip this cycle
        return;
    }

    // Step 4: Validate payload is non-empty
    if (payload.size() == 0U)
    {
        ReleaseMutex(g_sendBufferTimedMutex);
        return;
    }

    // Step 5: Invoke fire-and-forget UDP transmission
    SendDaqFireForgetMethod(CLIENT_ID_CONTINUAL_SHORT, PDU_ID_CONTINUAL_SHORT, payload);

    // Step 6: Clear the payload buffer after transmission
    const bool clearResult{ClearBuffer(payload)};
    if (clearResult == false)
    {
        // Step 6a: RAM cleanup failure - initiate application stop
        ReleaseMutex(g_sendBufferTimedMutex);
        InitiateApplicationStop();
        return;
    }

    // Step 7: Release mutex
    ReleaseMutex(g_sendBufferTimedMutex);
}

// ============================================================
// PC-035 — SendContinualLongDataCyclic1000ms
// ============================================================

/**
 * @brief Transmits long-cycle steady-state data to DAQ via SOME/IP UDP at 1000ms intervals.
 * @details Implements the 1000ms Cyclic Steady-State Long Data Transmission algorithm.
 *          Evaluates DAQ session state via SuppressDataBeforeDaqEstablished(). If the
 *          session is not established, returns immediately. Acquires sendBufferMutex via
 *          TryLockMutex with MAX_MUTEX_WAIT_MS. Validates payload is non-empty. Invokes
 *          SendDaqFireForgetMethod with CLIENT_ID_CONTINUAL_LONG and PDU_ID_CONTINUAL_LONG.
 *          Calls ClearBuffer to release the payload. If ClearBuffer fails, calls
 *          ReleaseMutex then InitiateApplicationStop. Otherwise releases the mutex.
 *
 * @param[in] payload Serialized long-cycle steady-state data. Must not be empty.
 *                    Maximum size defined by DAQ SOME/IP UDP MTU (1200 bytes).
 * @pre  FindServiceDaqContinual() has been called. daqCommunicationEstablished_ is true.
 * @post Payload is transmitted to DAQ if communication is established.
 * @throws None.
 * @note Called by: ProbeApp. Provides: CORE_DAQ_continual_Service. Cyclic: 1000ms.
 * @requirements SWR-REQ-01-002;SWR-REQ-01-06-001;SWR-REQ-01-05-001
 * @see SendDaqFireForgetMethod, SuppressDataBeforeDaqEstablished
 */
void ProbeComm::SendContinualLongDataCyclic1000ms(std::vector<uint8_t> payload) noexcept
{
    // Step 1: Check if DAQ SOME/IP communication is established
    if (SuppressDataBeforeDaqEstablished() == true)
    {
        // Step 2a: Session not yet established, suppress transmission
        return;
    }

    // Step 3: Acquire send buffer mutex with bounded wait
    const bool lockResult{TryLockMutex(g_sendBufferTimedMutex, MAX_MUTEX_WAIT_MS)};
    if (lockResult == false)
    {
        // Step 3a: Mutex acquisition failed, skip this cycle
        return;
    }

    // Step 4: Validate payload is non-empty
    if (payload.size() == 0U)
    {
        ReleaseMutex(g_sendBufferTimedMutex);
        return;
    }

    // Step 5: Invoke fire-and-forget UDP transmission for long-cycle data
    SendDaqFireForgetMethod(CLIENT_ID_CONTINUAL_LONG, PDU_ID_CONTINUAL_LONG, payload);

    // Step 6: Clear the payload buffer after transmission
    const bool clearResult{ClearBuffer(payload)};
    if (clearResult == false)
    {
        // Step 6a: RAM cleanup failure - initiate application stop
        ReleaseMutex(g_sendBufferTimedMutex);
        InitiateApplicationStop();
        return;
    }

    // Step 7: Release mutex
    ReleaseMutex(g_sendBufferTimedMutex);
}

// ============================================================
// PC-036 — SendDaqFireForgetMethod
// ============================================================

/**
 * @brief Transmits DAQ_UNIVERSAL_ETH_DATA_FIR_FGT message with client ID, PDU ID, and data vector.
 * @details Implements the DAQ Fire-and-Forget UDP Dispatch algorithm.
 *          Guards against transmission when daqCommunicationEstablished_ is false.
 *          Validates that dataVector is non-empty and does not exceed 1200 bytes.
 *          Constructs the payload fields uedClientId, uedPduId, uedDataVector and
 *          dispatches via CORE_DAQ_continual_Service.DAQ_UNIVERSAL_ETH_DATA_FIR_FGT().
 *          No acknowledgement is awaited; buffer lifecycle is owned by the calling unit.
 *
 * @param[in] clientId   DAQ client identifier. Valid range: [0x0000, 0xFFFF].
 * @param[in] pduId      PDU identifier for the data type. Valid range: [0x00000000, 0xFFFFFFFF].
 * @param[in] dataVector Serialized data payload. Must not be empty. Maximum 1200 bytes.
 * @pre  daqCommunicationEstablished_ is true. sendBufferMutex is held by caller.
 * @post Message is enqueued for UDP transmission to DAQ.
 * @throws None.
 * @note Called by: ProbeComm. Provides: CORE_DAQ_continual_Service. Cyclic: 100ms.
 * @requirements SWR-REQ-01-005;SWR-REQ-01-06-002;SWR-REQ-01-05-002
 * @see SendContinualShortDataCyclic100ms, SendContinualLongDataCyclic1000ms
 */
void ProbeComm::SendDaqFireForgetMethod(uint16_t              clientId,
                                         uint32_t              pduId,
                                         std::vector<uint8_t>  dataVector) noexcept
{
    // Step 1: Guard - suppress send if DAQ session is not established
    if (daqCommunicationEstablished_.load() == false)
    {
        // No session active; suppress transmission silently
        return;
    }

    // Step 2: Validate data vector bounds — empty payload is not valid
    if (dataVector.size() == 0U)
    {
        return;
    }

    // Payload exceeds maximum allowed size; suppress send
    if (dataVector.size() > kMaxDaqFireForgetPayloadBytes)
    {
        return;
    }

    // Step 3: Construct payload fields per Constant Data Payload Layout
    const uint16_t uedClientId{clientId};
    const uint32_t uedPduId{pduId};
    const std::vector<uint8_t> uedDataVector{dataVector};

    // Step 4: Invoke SOME/IP UDP fire-and-forget method on CORE_DAQ_continual_Service
    g_daqContinualServiceProxy.DAQ_UNIVERSAL_ETH_DATA_FIR_FGT(uedClientId,
                                                                uedPduId,
                                                                uedDataVector);

    // No return value or acknowledgement is expected (fire-and-forget)
    // Step 5: Return; buffer lifecycle managed by calling unit
}

// ============================================================
// PC-037 — SuppressDataBeforeDaqEstablished
// ============================================================

/**
 * @brief Returns true to suppress data transmission when SOME/IP communication with DAQ is not yet established.
 * @details Implements the DAQ Session Guard Predicate algorithm.
 *          Reads daqCommunicationEstablished_ atomically. Returns true (suppress) when
 *          the flag is false, and false (allow) when the flag is true. Introduces no
 *          side effects and does not modify any state.
 *
 * @return bool Indicates whether data transmission should be suppressed.
 * @retval true  DAQ communication is not established; suppress transmission.
 * @retval false DAQ communication is established; transmission is allowed.
 * @pre  None.
 * @post No state is modified.
 * @throws None.
 * @note Called by: ProbeComm. Condition: On_Request.
 * @requirements SWR-REQ-01-04-001;SWR-REQ-01-04-002
 * @see FindServiceDaqContinual
 */
bool ProbeComm::SuppressDataBeforeDaqEstablished() const noexcept
{
    // Step 1: Read DAQ communication establishment flag
    if (daqCommunicationEstablished_.load() == false)
    {
        // Session not active; caller must suppress transmission
        return true;
    }
    else
    {
        // Session is active; caller may proceed with transmission
        return false;
    }
}

// ============================================================
// PC-038 — SendImageAcquisitionTriggerToCameraHost
// ============================================================

/**
 * @brief Sends trigger message to CameraHost when event data generation starts.
 * @details Implements the Image Acquisition Trigger Dispatch algorithm.
 *          Validates PROBE_TRG_Service proxy availability via IsAvailable(). If the
 *          service is unavailable, returns immediately without sending; the downstream
 *          AbortImageProcessingBeforeTransmitPhase() will detect the missing answer-back.
 *          When available, constructs the ADAS_PROBE2CAM_EVT payload with
 *          ImageReq_Trigger = 1, ADAS_EVT_Info = eventInfo, Number_of_EVT = numEvt,
 *          and publishes the event through PROBE_TRG_Service. No answer-back is awaited
 *          here; asynchronous reception is handled by HandleCam2ProbeAnswerBackEvt().
 *
 * @param[in] eventInfo  Event information field for the trigger message.
 *                       Valid range: [0x00000000, 0xFFFFFFFF].
 * @param[in] numEvt     Number of events field for the trigger message.
 *                       Valid range: [0x00, 0xFF].
 * @pre  OfferServiceProbeTrigger() has been called. CameraHost is subscribed.
 * @post ADAS_PROBE2CAM_EVT is sent. Image acquisition timeout timer is started.
 * @throws None.
 * @note Called by: ProbeApp. Provides: PROBE_TRG_Service. Condition: Event_Trigger.
 * @requirements SWR-REQ-03-06-001;SWR-REQ-03-18-001
 * @see HandleCam2ProbeAnswerBackEvt, AbortImageProcessingBeforeTransmitPhase
 */
void ProbeComm::SendImageAcquisitionTriggerToCameraHost(uint32_t eventInfo,
                                                         uint8_t  numEvt) noexcept
{
    // Step 1: Validate PROBE_TRG_Service proxy availability
    if (g_probeTrgServiceProxy.IsAvailable() == false)
    {
        // Service not available; image acquisition cannot be initiated.
        // Image acquisition pipeline will be detected as not started downstream.
        return;
    }

    // Step 2: Construct ADAS_PROBE2CAM_EVT payload
    // ImageReq_Trigger field <- 1 (trigger request active)
    // ADAS_EVT_Info          <- eventInfo
    // Number_of_EVT          <- numEvt

    // Step 3: Publish trigger event to CameraHost via PROBE_TRG_Service
    g_probeTrgServiceProxy.ADAS_PROBE2CAM_EVT(
        static_cast<uint8_t>(1U),   // ImageReq_Trigger = 1
        eventInfo,                   // ADAS_EVT_Info
        numEvt                       // Number_of_EVT
    );

    // No acknowledgement awaited here; async answer-back handled by HandleCam2ProbeAnswerBackEvt
}

// ============================================================
// PC-039 — ReceiveCameraImages
// ============================================================

/**
 * @brief Receives 14 JPEG images covering -5 to +8 seconds around the event with timeout enforcement.
 * @details Implements the Bounded Image Acquisition Monitoring with Timeout algorithm.
 *
 *          Step 1: Acquires cameraMutex and starts the timeout timer by setting
 *          imageTimeoutTimerStarted_ to true if not already set, then releases the mutex.
 *
 *          Step 2: Computes maxIterations as (imageAcquisitionTimeoutSec_ * 1000) / 100
 *          to derive the bounded upper limit for the polling loop. Initialises iterationCount to 0.
 *
 *          Step 3: Enters a bounded polling loop (while iterationCount < maxIterations).
 *          On each iteration: acquires cameraMutex to read imageAcquisitionComplete_ into
 *          localComplete and receivedImageCount_ into localCount, then releases the mutex.
 *          If localComplete is true, exits the loop. If localCount >= 14, acquires cameraMutex,
 *          sets imageAcquisitionComplete_ to true, releases the mutex, and exits the loop.
 *          Calls EnforceImageAcquisitionTimeout(); if it returns true, exits the loop.
 *          Otherwise sleeps 100ms and increments iterationCount.
 *
 *          Step 4: After the loop, acquires cameraMutex to read imageAcquisitionComplete_.
 *          If still false, releases the mutex and calls AbortImageAcquisitionOnTimeout().
 *          Otherwise releases the mutex and returns normally.
 *
 * @pre  SendImageAcquisitionTriggerToCameraHost() has been called.
 *       cameraAnswerBackReceived_ is true.
 * @post imageAcquisitionComplete_ is true if all 14 images received.
 *       imageAcquisitionComplete_ remains false if timeout occurred.
 * @throws None.
 * @note Called by: ProbeComm. Provides: CameraHost_IMG_Service. Condition: Event_Trigger.
 * @warning This function may block for up to imageAcquisitionTimeoutSec_ seconds.
 * @requirements SWR-REQ-03-06-006;SWR-REQ-03-06-010
 * @see EnforceImageAcquisitionTimeout, AbortImageAcquisitionOnTimeout
 */
void ProbeComm::ReceiveCameraImages() noexcept
{
    // Step 1: Start timeout timer if not already started
    {
        std::lock_guard<std::timed_mutex> lock(g_cameraTimedMutex);
        if (imageTimeoutTimerStarted_ == false)
        {
            imageTimeoutTimerStarted_ = true;
            // Record timer start reference for EnforceImageAcquisitionTimeout
            imageTimeoutStartPoint_= std::chrono::steady_clock::now();
        }
    }

    // Step 2: Compute max polling iterations from timeout and sleep interval
    // maxIterations = imageAcquisitionTimeoutSec_ * 1000 / 100
    // (imageAcquisitionTimeoutSec_ default = 55, sleep = 100ms -> max 550 iterations)
    const uint32_t maxIterations{(imageAcquisitionTimeoutSec_ * 1000U) / kImagePollSleepMs};
    uint32_t iterationCount{0U};

    // Step 3: Bounded polling loop - max iterations enforced
    while (iterationCount < maxIterations)
    {
        // Step 3a: Check if acquisition is complete
        bool localComplete{false};
        uint8_t localCount{0U};

        {
            std::lock_guard<std::timed_mutex> lock(g_cameraTimedMutex);
            localComplete = imageAcquisitionComplete_;
            localCount    = receivedImageCount_;
        }

        if (localComplete == true)
        {
            // All images received or already aborted; exit loop
            break;
        }

        if (static_cast<uint32_t>(localCount) >= static_cast<uint32_t>(kExpectedImageCount))
        {
            // All 14 images received; mark complete
            std::lock_guard<std::timed_mutex> lock(g_cameraTimedMutex);
            imageAcquisitionComplete_ = true;
            break;
        }

        // Step 3b: Check timeout via EnforceImageAcquisitionTimeout
        const bool timeoutExpired{EnforceImageAcquisitionTimeout()};
        if (timeoutExpired == true)
        {
            // Timeout handler has already called AbortImageAcquisitionOnTimeout
            // imageAcquisitionComplete_ is set to true by that call
            break;
        }

        // Step 3c: Sleep 100ms before next poll
        std::this_thread::sleep_for(std::chrono::milliseconds(static_cast<int64_t>(kImagePollSleepMs)));
        iterationCount = iterationCount + 1U;
    }

    // Step 4: Final safety check - if loop exited by max iterations without completion, abort
    {
        std::lock_guard<std::timed_mutex> lock(g_cameraTimedMutex);
        if (imageAcquisitionComplete_ == false)
        {
            // Max iterations reached; force abort
            // Release before calling abort to avoid recursive lock
        }
        else
        {
            return;
        }
    }

    // imageAcquisitionComplete_ was false after loop; call abort outside the lock
    AbortImageAcquisitionOnTimeout();
}

// ============================================================
// PC-040 — ValidateCameraAnswerBack
// ============================================================

/**
 * @brief Evaluates acceptance status from CameraHost answer back message.
 * @details Implements the CameraAnswerBack Acceptance Status Evaluation algorithm.
 *          Initialises a local result variable to false. Extracts the acceptance status
 *          from the answerBack byte into acceptanceStatus. If acceptanceStatus equals
 *          the defined acceptance code (0x01), sets cameraAnswerBackReceived_ to true
 *          and result to true. Otherwise sets cameraAnswerBackReceived_ to false and
 *          result to false. Returns result.
 *
 *          This function performs no dynamic allocation, no external service call,
 *          and completes in bounded time regardless of input. All conditional paths
 *          have an explicit defined outcome.
 *
 * @param[in] answerBack Answer back status byte from CameraHost.
 *                       Valid range: [0x00, 0xFF]. 0x01 = accepted, others = rejected.
 * @return bool Indicates whether CameraHost accepted the trigger.
 * @retval true  CameraHost accepted the image acquisition trigger (answerBack == 0x01).
 * @retval false CameraHost rejected the image acquisition trigger (answerBack != 0x01).
 * @pre  answerBack has been extracted from a valid CameraHost answer back message.
 * @post cameraAnswerBackReceived_ is updated to reflect the acceptance status.
 * @throws None.
 * @note Called by: ProbeComm. Condition: Event_Trigger.
 * @requirements SWR-REQ-03-06-002;SWR-REQ-03-06-003
 * @see HandleCam2ProbeAnswerBackEvt, AbortImageProcessingBeforeTransmitPhase
 */
bool ProbeComm::ValidateCameraAnswerBack(uint8_t answerBack) noexcept
{
    // Step 1: Define local result, initialised to rejection state
    bool result{false};

    // Step 2: Extract acceptance status from the answer back byte
    // Acceptance is indicated when the status field is a non-error acceptance code
    const uint8_t acceptanceStatus{answerBack};

    // Step 3: Evaluate acceptance status
    if (acceptanceStatus == kCameraAnswerBackAccepted)
    {
        // Step 3a: Mark answer back as received and accepted
        cameraAnswerBackReceived_ = true;
        result = true;
    }
    else
    {
        // Step 3b: Mark answer back as not accepted; triggers suppression in caller
        cameraAnswerBackReceived_ = false;
        result = false;
    }

    // Step 4: Return the validation result
    return result;
}

